import type { Drill } from "./types";

// Education / senior drills, keyed by module slug — 25 per module.
// Principal / dean / education administrator: board presentations, community letters,
// budget cases to the district, personnel decisions, crisis communications, union
// negotiation, enrollment strategy. Merged into course.ts.
export const EDUCATION_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-edu-senior-01","level":"senior","profession":"education","title":"The enrollment update that buries the number","scenario":"You're presenting the fall enrollment report to the school board. The headline is a 6% decline — 74 students — that will drive next year's budget. Your draft opens with three slides on registration procedures before the number appears.","task":"Write the first two sentences of your board remarks, leading with the enrollment number and what it means.","tips":["Sentence one: the number and the direction.","Sentence two: the consequence the board must plan for.","Procedures and methodology can wait for questions."],"focus":["structure","impact"],"placeholder":"Enrollment is down 74 students — 6% — and that drives a budget gap of roughly $610,000 next year."},
    {"id":"lead-edu-senior-02","level":"senior","profession":"education","title":"The roof repair ask to the superintendent","scenario":"The gym roof failed inspection and the repair can't wait for the summer capital cycle. You need $180,000 released now, and only the superintendent can authorize it. Your draft email spends two paragraphs on the inspection history before making the request.","task":"Write a 2-3 sentence email that puts the ask and the deadline in the first sentence.","tips":["Lead with the amount, the purpose, and when you need the decision.","The inspection report is an attachment, not the opening.","Say what happens if the answer is slow — one sentence, factual."],"focus":["clarity","impact"],"placeholder":"I'm requesting $180,000 from the emergency facilities reserve to repair the gym roof, with a decision needed by Friday —"},
    {"id":"lead-edu-senior-03","level":"senior","profession":"education","title":"The master-schedule email to staff","scenario":"After months of committee work, you've decided: next year the school moves to a seven-period day. Staff have been waiting for the decision. Your draft email recounts the committee's process for four paragraphs before announcing the outcome.","task":"Rewrite the opening so the decision is the first sentence, then write one sentence pointing to details.","tips":["Staff scan for the verdict — give it in line one.","The committee's process earns trust as support, not as preamble.","Name where full details live and when questions can be asked."],"focus":["clarity","structure"]},
    {"id":"lead-edu-senior-04","level":"senior","profession":"education","title":"The bus-route letter home","scenario":"Starting Monday, three bus routes change and about 200 families will have new pickup times. Your draft letter opens with background on the transportation contract before saying anything a parent can act on.","task":"Write the first two sentences of the family letter, leading with what changes and when.","tips":["Parents need the action first: new times, starting Monday.","Point to where each family finds their specific route.","The contract backstory helps almost no one — cut or bury it."],"focus":["audience","clarity"],"placeholder":"Starting Monday, October 6, bus routes 3, 7, and 11 have new pickup times."},
    {"id":"lead-edu-senior-05","level":"senior","profession":"education","title":"The incident report that hides severity","scenario":"A student broke an arm in a hallway altercation this morning; the family has been notified and the student is stable. District policy requires you to notify the assistant superintendent today. Your draft narrates the morning chronologically, and the injury appears in paragraph three.","task":"Write a 2-3 sentence notification that leads with what happened and the current status.","tips":["First sentence: the incident, the injury, the student's status.","Second: what's been done — family contacted, report filed.","Chronology belongs in the formal incident report, not the alert."],"focus":["clarity","precision"],"placeholder":"A student sustained a broken arm in a hallway altercation this morning; the family has been notified and the student is stable at Mercy General."},
    {"id":"lead-edu-senior-06","level":"senior","profession":"education","title":"The Friday bulletin with one real action item","scenario":"Your weekly staff bulletin covers eight items, but only one requires action: grades are due in the portal by Tuesday noon, a day earlier than usual because of conferences. Your draft lists items in the order you thought of them, and the deadline sits at item six.","task":"Write the bulletin's opening line so the one action item leads.","tips":["Lead with the item that has a deadline and a consequence.","Label it as the action item so skimmers can't miss it.","Everything informational follows in any order."],"focus":["structure","concision"]},
    {"id":"lead-edu-senior-07","level":"senior","profession":"education","title":"The board agenda request","scenario":"You want fifteen minutes on next month's board agenda to present your counselor staffing proposal before budget season closes. Your email to the board chair opens with pleasantries and context about student mental health trends before the actual request.","task":"Write a 2-3 sentence email that leads with the agenda request and the timing constraint.","tips":["First sentence: what you're asking for and for which meeting.","Say why it can't wait — one clause, not a paragraph.","Make it easy to say yes: state the time you need."],"focus":["clarity","concision"],"placeholder":"I'd like 15 minutes on the November 12 agenda to present the counselor staffing proposal —"},
    {"id":"lead-edu-senior-08","level":"senior","profession":"education","title":"The board member's data question","scenario":"A board member emailed asking one question: how many students left for the charter school this year? The answer is 41. Your draft reply explains your data sources, caveats about mid-year transfers, and enrollment context for three paragraphs before the number appears.","task":"Write a reply that gives the number in the first sentence, with one caveat after.","tips":["Answer the question asked, first, in plain numbers.","One caveat, clearly labeled, is enough — offer detail on request.","Board members forward answers; make the first line quotable and accurate."],"focus":["precision","concision"],"placeholder":"41 students transferred to Harmony Charter this year."},
    {"id":"lead-edu-senior-09","level":"senior","profession":"education","title":"The closure recommendation to the district","scenario":"Ice is forecast for 5 a.m. and you believe your rural routes will be impassable. The transportation director needs your recommendation by 8 p.m. to coordinate the district decision. Your draft walks through the forecast models before stating your position.","task":"Write a 2-sentence message that leads with your recommendation.","tips":["First words: your call — close, delay, or open.","One sentence of grounds: which routes, what conditions.","The forecast detail is available if they ask; don't pre-load it."],"focus":["clarity","impact"]},
    {"id":"lead-edu-senior-10","level":"senior","profession":"education","title":"The testing-window slip","scenario":"The state moved your school's assessment window back two weeks, which collides with the spring concert and AP exams. Teachers need the new dates to replan units. Your draft memo opens with an explanation of the state's scheduling system.","task":"Write a memo opening that states the new dates and the immediate implication first.","tips":["Lead with the new window — dates teachers can put in calendars.","Name the collision you already see; invite others.","Why the state moved it is a footnote."],"focus":["clarity","structure"],"placeholder":"The state assessment window has moved to April 20 – May 1."},
    {"id":"lead-edu-senior-11","level":"senior","profession":"education","title":"The hiring exception request","scenario":"Your best candidate for the physics opening is a career-changer who needs an alternative-certification waiver, and HR has asked for your recommendation. You have a clear position: hire her. Your draft memo weighs both sides for a page before landing anywhere.","task":"Rewrite the memo opening so your recommendation comes first, then the two strongest reasons.","tips":["State your recommendation in sentence one.","Give the top reasons, not all of them.","A balanced tone doesn't require hiding your conclusion."],"focus":["structure","clarity"],"placeholder":"I recommend we hire Dana Okafor for the physics position under an alternative-certification waiver."},
    {"id":"lead-edu-senior-12","level":"senior","profession":"education","title":"The PTA funding ask","scenario":"You're asking the PTA for $4,500 to replace the aging document cameras in twelve classrooms before the spring. Your draft speech to the PTA meeting spends five minutes on the year's accomplishments before mentioning money.","task":"Write the first two sentences of your ask, leading with the amount and the purpose.","tips":["State the number and what it buys in sentence one.","Sentence two: the classroom impact, concretely.","Gratitude and accomplishments frame the close, not the open."],"focus":["clarity","impact"]},
    {"id":"lead-edu-senior-13","level":"senior","profession":"education","title":"The stalled work order","scenario":"You submitted a work order three weeks ago for the broken exterior door lock on the east entrance — a safety issue — and facilities hasn't responded. Your follow-up draft opens with an apology for bothering them.","task":"Write a follow-up that leads with the specific request, the safety stake, and a date.","tips":["Lead with what you need and by when.","Name the safety issue plainly — it justifies the urgency.","Reference the work-order number so no one has to search."],"focus":["clarity","impact"],"placeholder":"I need work order 4417 — the east-entrance lock — completed this week; it's a building-security issue."},
    {"id":"lead-edu-senior-14","level":"senior","profession":"education","title":"The note to the union rep","scenario":"You want to meet with the building union rep this week to discuss the morning-duty schedule before you finalize it, because changing it later would trigger a grievance. Your draft message meanders through the history of the duty roster first.","task":"Write a 2-sentence message that leads with the meeting request and the topic.","tips":["First sentence: the ask — a meeting, this week, on the duty schedule.","Signal that you want input before the decision, not after.","History can come to the meeting, not the message."],"focus":["clarity","audience"]},
    {"id":"lead-edu-senior-15","level":"senior","profession":"education","title":"The projection memo","scenario":"The district planning office asked for your five-year enrollment projection. Your model says the school shrinks from 620 to roughly 540. Your draft memo opens with a description of the cohort-survival method.","task":"Write a memo opening that leads with the projection, then names the method in one clause.","tips":["The number is the news — lead with it and the range.","Name the method briefly for credibility, then move on.","Say what the projection means for staffing in one sentence."],"focus":["precision","structure"],"placeholder":"We project enrollment falling from 620 to approximately 540 over five years —"},
    {"id":"lead-edu-senior-16","level":"senior","profession":"education","title":"The grant verdict","scenario":"The literacy grant you applied for came through: $95,000 over two years. The district grants office and your leadership team are waiting on the outcome. Your draft update tells the story of the application process from the beginning.","task":"Write a 2-sentence update that leads with the award and the first consequence.","tips":["First sentence: awarded, how much, over what period.","Second: the first thing it funds and when it starts.","The application saga is for the celebration, not the update."],"focus":["clarity","concision"],"placeholder":"We won the Riverton Literacy Grant: $95,000 over two years, starting January."},
    {"id":"lead-edu-senior-17","level":"senior","profession":"education","title":"The drill debrief with one gap","scenario":"Yesterday's lockdown drill went smoothly except for one serious gap: the portable classrooms couldn't hear the announcement. Your debrief email to staff opens with thanks and a walkthrough of everything that went well.","task":"Write a debrief opening that leads with the gap and the fix, then credits what worked.","tips":["Safety gaps lead — that's the sentence people must read.","Pair the gap with the corrective action and its date.","Appreciation is real but comes second."],"focus":["structure","impact"]},
    {"id":"lead-edu-senior-18","level":"senior","profession":"education","title":"The mid-year staffing letter","scenario":"Your fifth-grade teacher is leaving in three weeks for a family relocation, and a permanent replacement starts the Monday after she leaves. Families will worry most about continuity. Your draft letter opens with a tribute to the departing teacher.","task":"Write the first two sentences of the letter, leading with the change and the continuity plan.","tips":["Parents' first question is who teaches my child and when — answer it first.","Name the incoming teacher and the start date in the opening.","The tribute belongs in the letter, just not in line one."],"focus":["audience","clarity"],"placeholder":"Ms. Reyes will be leaving Grade 5 on November 21, and Mr. Patel — currently our reading interventionist — takes over the class the following Monday."},
    {"id":"lead-edu-senior-19","level":"senior","profession":"education","title":"The overtime yes/no","scenario":"The superintendent texts you one question before a budget meeting: did your building exceed its overtime allocation this quarter? The answer is yes, by about $6,200, driven by the boiler failure. Your draft reply starts with the boiler story.","task":"Write a reply that answers yes/no first, then gives the number and the driver.","tips":["Answer in the first word.","Follow with the amount and the single biggest cause.","Offer the breakdown, don't paste it."],"focus":["concision","precision"],"placeholder":"Yes — over by about $6,200, almost entirely the boiler failure in January."},
    {"id":"lead-edu-senior-20","level":"senior","profession":"education","title":"The eligibility heads-up","scenario":"You've just learned a starting player on the basketball team may have been academically ineligible for two games — which could mean forfeits. The athletic director and district need to hear it from you before it circulates. Your draft softens toward the point.","task":"Write a 2-3 sentence heads-up that states the issue and the possible consequence first.","tips":["Lead with the issue and the worst plausible outcome.","Say what's confirmed versus still being verified.","Name your next step and when they'll hear more."],"focus":["clarity","precision"]},
    {"id":"lead-edu-senior-21","level":"senior","profession":"education","title":"The substitute-budget flag","scenario":"It's February and you've spent 82% of your annual substitute budget, driven by long-term medical leaves. The finance office should hear this from you now, not discover it in April. Your draft email opens by describing the flu season.","task":"Write an email opening that leads with the number and the projected year-end position.","tips":["Lead with the percentage spent and the months remaining.","Project the year-end overage — a range is fine.","Causes come second; proposed offsets third."],"focus":["precision","impact"],"placeholder":"We've spent 82% of the substitute budget with four months left — projecting a $28,000–$35,000 overage by June."},
    {"id":"lead-edu-senior-22","level":"senior","profession":"education","title":"The principal's report opener","scenario":"Your monthly principal's report to the board is five minutes long. This month the story that matters is that the new reading block moved mid-year benchmark scores up 9 points. Your draft opens with a list of upcoming events.","task":"Write the first sentence of your report, leading with the result the board should remember.","tips":["Open with the outcome, with the number attached.","Events and calendar items close the report, not open it.","One memorable sentence beats three minutes of throat-clearing."],"focus":["impact","structure"]},
    {"id":"lead-edu-senior-23","level":"senior","profession":"education","title":"The counselor FTE request","scenario":"You're emailing the assistant superintendent to request a second full-time counselor for next year. Your caseload is 480 students per counselor against a recommended 250. Your draft builds the case slowly and asks at the end.","task":"Write a 2-3 sentence opening that puts the ask — one FTE, next year — in sentence one.","tips":["Lead with exactly what you're requesting and for when.","The 480-vs-250 ratio is your best sentence-two evidence.","One clear ask per email; details in the attached proposal."],"focus":["clarity","impact"],"placeholder":"I'm requesting one additional full-time counselor for next school year."},
    {"id":"lead-edu-senior-24","level":"senior","profession":"education","title":"The water-main message","scenario":"A water main broke this afternoon; repairs run overnight and school will open two hours late tomorrow. Staff need to know now what tomorrow looks like. Your draft explains the plumbing situation before the schedule.","task":"Write the first two sentences of the staff message, leading with tomorrow's plan.","tips":["Lead with the operational fact: two-hour delay tomorrow.","Then the two things staff must do differently.","The pipe is context — one clause at most."],"focus":["clarity","concision"],"placeholder":"School opens two hours late tomorrow — staff report at 9:30, students at 10:00."},
    {"id":"lead-edu-senior-25","level":"senior","profession":"education","title":"The partner thank-you with a new ask","scenario":"The local credit union funded your mentorship program this year, and you now want them to sponsor its expansion to eighth grade — a decision their board makes next month. Your draft letter is two paragraphs of gratitude with the new ask hidden in the final line.","task":"Rewrite the opening so the expansion ask is clear in the first two sentences, gratitude alongside it.","tips":["Pair the thanks and the ask in the opening — both visible.","Name the decision and its deadline so their board can act.","Warmth and directness are not in conflict."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-edu-senior-01","level":"senior","profession":"education","title":"MTSS for the newsletter","scenario":"Your improvement plan centers on MTSS — multi-tiered systems of support. The draft newsletter item reads: \"We are implementing Tier 2 progress-monitoring protocols within our MTSS framework.\" Families have no idea what that means for their child.","task":"Rewrite the item in 2-3 sentences a parent with no education background understands.","tips":["Translate the framework into what happens to a struggling child, and when.","Cut the tier labels or define one in passing.","End with what a parent should do if they're worried about their child."],"focus":["audience","clarity"],"placeholder":"When a student starts falling behind in reading or math, we now catch it within weeks — not at report-card time."},
    {"id":"audience-edu-senior-02","level":"senior","profession":"education","title":"Absenteeism for the board","scenario":"Chronic absenteeism at your school hit 18%. For the board, the stake isn't pedagogy — it's outcomes and funding: absent students fail courses, and enrollment-based revenue follows attendance. Your draft slide defines absenteeism categories in education jargon.","task":"Write 2-3 sentences framing the absenteeism problem in terms the board acts on.","tips":["Lead with the board's stake: outcomes and dollars, not definitions.","One number for scale, one for consequence.","Save intervention taxonomy for the appendix."],"focus":["audience","impact"]},
    {"id":"audience-edu-senior-03","level":"senior","profession":"education","title":"Special education staffing for the CFO","scenario":"You need another special-education aide. To you it's about IEP minutes and student need; to the district CFO it's about compliance exposure and cost. Your draft memo argues entirely from student-centered language the CFO can't weigh against other requests.","task":"Rewrite your 2-3 sentence case in terms of compliance risk and cost the CFO can act on.","tips":["Lead with the compliance gap: IEP minutes legally owed versus staffed.","Put a number on the risk — due-process complaints have a price.","Keep the student story to one grounding clause."],"focus":["audience","precision"],"placeholder":"We are currently unable to deliver 340 legally required IEP service minutes per week —"},
    {"id":"audience-edu-senior-04","level":"senior","profession":"education","title":"The new reading curriculum, for parents","scenario":"You're announcing a switch to a structured-literacy curriculum. The draft letter talks about \"phonemic awareness sequences\" and \"decodable texts.\" A parent wants to know one thing: will my child read better, and what changes for them.","task":"Write a 2-3 sentence announcement centered on the child's experience.","tips":["Answer the parent's real question first: what changes for my kid.","One concrete detail — what homework or reading time looks like now.","Name the evidence in plain words: this method works for more kids."],"focus":["audience","clarity"]},
    {"id":"audience-edu-senior-05","level":"senior","profession":"education","title":"The data-system change, for teachers","scenario":"The district is replacing the student-information system over winter break. The district memo is written for IT. Your teachers need to know exactly one thing: what they must do differently on the first Monday back.","task":"Write a 2-3 sentence staff note that leads with what changes for teachers on day one.","tips":["Translate the migration into Monday-morning actions.","Name the one task with a deadline — new login, grade export.","Link the IT memo for the curious; don't forward it as the message."],"focus":["audience","clarity"],"placeholder":"When we return January 5, you'll take attendance and enter grades in PowerSchool instead of Infinite Campus."},
    {"id":"audience-edu-senior-06","level":"senior","profession":"education","title":"The score dip, for the local paper","scenario":"State results dropped and your school's math proficiency fell 4 points. A reporter from the local paper asks you to explain. Your instinct is to talk about cohort effects and standard-setting changes — accurate, but it will read as excuse-making.","task":"Write a 2-3 sentence quote in plain language that is honest about the dip and concrete about the response.","tips":["Say the plain fact first — scores fell — before any context.","One piece of context, in words a non-educator uses.","End on the specific action, not a vague commitment to excellence."],"focus":["audience","precision"]},
    {"id":"audience-edu-senior-07","level":"senior","profession":"education","title":"Orientation for the new board member","scenario":"A newly elected board member — a retired contractor, sharp but new to education — asked you to explain your school-improvement plan. Your standing deck assumes fluency in benchmarks, cohorts, and Title I. He'll be voting on your budget in March.","task":"Write a 3-4 sentence overview of your improvement plan that assumes no education background.","tips":["Pick the three things he must understand to vote well — drop the rest.","Define terms by their function: Title I means extra federal money for schools with more low-income students.","Respect his intelligence; skip only the vocabulary, not the substance."],"focus":["audience","structure"],"placeholder":"Our plan comes down to three moves: catch struggling readers earlier, keep more students in class, and hold onto good teachers."},
    {"id":"audience-edu-senior-08","level":"senior","profession":"education","title":"The schedule change, for operations staff","scenario":"Next semester's bell-schedule change shifts lunch service 40 minutes earlier and moves the custodial day. Your draft memo to food-service and custodial staff is the same one you sent teachers, full of instructional-minutes rationale.","task":"Rewrite the memo opening in 2-3 sentences focused on what changes for their workday.","tips":["Lead with their new times, not the instructional reasoning.","Name who to raise conflicts with, by when.","Plain respect: no education jargon, no talking down."],"focus":["audience","clarity"]},
    {"id":"audience-edu-senior-09","level":"senior","profession":"education","title":"Early-release days, for skeptical parents","scenario":"You're adding monthly early-release days for teacher collaboration. To parents this reads as less school and a childcare problem. Your draft defends \"professional learning communities\" — a phrase that lands as jargon justifying inconvenience.","task":"Write a 2-3 sentence explanation that takes the parent cost seriously and translates the benefit.","tips":["Acknowledge the real cost to families first — credibility before persuasion.","Translate PLC into an outcome: teachers aligning so no child falls through gaps between classrooms.","Say what you're doing about the childcare gap."],"focus":["audience","impact"]},
    {"id":"audience-edu-senior-10","level":"senior","profession":"education","title":"The compliance finding, for staff","scenario":"The state audit found your school out of compliance on ELL service documentation. The official finding is dense regulatory language. Staff need to know: what this means, whether anyone is in trouble, and what changes.","task":"Write a 3-4 sentence staff explanation that answers those three questions in order.","tips":["Defuse the fear first: is anyone in trouble? Answer it plainly.","Translate the finding into the one practice that changes.","Regulatory citations go in a footnote, not the message."],"focus":["audience","structure"],"placeholder":"The state found gaps in how we document ELL services — a paperwork problem, not a people problem, and no one is being disciplined."},
    {"id":"audience-edu-senior-11","level":"senior","profession":"education","title":"One memo, two audiences","scenario":"You drafted a staff memo about tightening morning supervision after a near-miss in the parking lot. You know parents will see it — staff memos leak within hours. Written for both audiences at once, it will serve neither.","task":"Decide the primary audience and write the 2-3 sentence version for them, noting in one line what the other audience gets instead.","tips":["Pick one primary reader; write a separate piece for the other.","Staff need duties and times; parents need reassurance and drop-off rules.","A leaked memo should still read as professional and calm — assume it travels."],"focus":["audience","clarity"]},
    {"id":"audience-edu-senior-12","level":"senior","profession":"education","title":"The bond measure, for voters without kids","scenario":"The district's facilities bond is on the ballot, and 70% of voters have no children in schools. Your community-forum remarks currently argue from student experience alone. These voters weigh property values, taxes, and civic return.","task":"Write 2-3 sentences making the bond case to a voter with no children in the system.","tips":["Meet them where their stake is: property values, safe community assets, tax cost in real terms.","One concrete number: what it costs the median homeowner per month.","Keep the student benefit but frame it as community return."],"focus":["audience","impact"],"placeholder":"For the median homeowner, this bond costs about $9 a month — and it's the difference between a 60-year-old building losing value and a modern one anchoring the neighborhood."},
    {"id":"audience-edu-senior-13","level":"senior","profession":"education","title":"The altitude check from the superintendent","scenario":"The superintendent asks for your enrollment story in three sentences for her board briefing. Your draft dives into building-level detail: kindergarten section counts, boundary-line effects, one family's transfer saga. She needs the district-level shape.","task":"Write the 3-sentence version at the altitude a superintendent presents to a board.","tips":["Trend, cause, ask — one sentence each.","Building-level detail only if it changes the district decision.","She should be able to say your sentences verbatim."],"focus":["audience","concision"]},
    {"id":"audience-edu-senior-14","level":"senior","profession":"education","title":"Restorative discipline, for the SRO","scenario":"You're shifting some discipline responses from suspension to restorative conferences. Your school resource officer worries this means consequences disappear. Your draft explanation, written in restorative-practice vocabulary, confirms his suspicion that it's soft.","task":"Write a 2-3 sentence explanation in operational terms he'll recognize, honest about what changes and what doesn't.","tips":["Say plainly what still triggers suspension — the line hasn't vanished.","Frame restorative conferences as accountability with a process, not instead of one.","Drop the vocabulary; keep the mechanics."],"focus":["audience","precision"]},
    {"id":"audience-edu-senior-15","level":"senior","profession":"education","title":"The conference notice for ELL families","scenario":"Parent-teacher conference signups open Monday. A third of your families speak limited English, and the notice will be machine-translated into four languages. Long sentences, idioms, and embedded clauses translate badly.","task":"Write the 3-sentence notice in short, simple sentences that survive translation.","tips":["One idea per sentence; no idioms, no nested clauses.","Concrete nouns and dates: who, what, when, how to sign up.","Read it back imagining a literal translation — does it still work?"],"focus":["audience","clarity"],"placeholder":"Parent-teacher conferences are November 13 and 14. You will meet your child's teacher for 20 minutes."},
    {"id":"audience-edu-senior-16","level":"senior","profession":"education","title":"The evaluation change, for the union","scenario":"The district is adding student-growth measures to teacher evaluations. Your note to the union leadership drafts like a district press release — all benefits. The union reads every sentence for one thing: how this affects their members' ratings and job security.","task":"Write a 2-3 sentence note to the union that addresses their members' stake directly.","tips":["Name their concern before they raise it: what this means for ratings.","Be specific about safeguards — weighting, appeal rights, phase-in.","An honest sentence about uncertainty beats a glossy one they won't believe."],"focus":["audience","precision"]},
    {"id":"audience-edu-senior-17","level":"senior","profession":"education","title":"The foundation report","scenario":"The family foundation funding your tutoring program asked for a renewal report. Your draft describes activities: sessions held, curriculum used, staff trained. Foundations fund outcomes — what changed for kids — and decide renewals on that.","task":"Rewrite the report opening in 2-3 sentences that lead with outcomes, not activities.","tips":["Lead with the change in student results, with numbers.","One vivid specific — a student or classroom — makes the number real.","Activities appear only as the mechanism that produced the outcome."],"focus":["audience","impact"],"placeholder":"Of the 60 students in the tutoring program, 44 moved up at least one reading level this year —"},
    {"id":"audience-edu-senior-18","level":"senior","profession":"education","title":"The phone policy, for students","scenario":"You're announcing the new phone policy — devices in pouches during class — at a student assembly. Your draft sounds like the policy manual: \"non-instructional device usage.\" Students will decide in the first ten seconds whether to take it seriously or mock it.","task":"Write the first 2-3 sentences of your assembly remarks in language that is direct, respectful, and unmistakably clear.","tips":["Say exactly what happens and when it starts — no policy vocabulary.","Give the real reason in one honest sentence; students detect spin instantly.","Respect earns compliance; sarcasm and threats forfeit it."],"focus":["audience","clarity"]},
    {"id":"audience-edu-senior-19","level":"senior","profession":"education","title":"The budget cut, told to the PTA","scenario":"Next year's budget cuts a library-assistant position. You've briefed staff with FTE tables and attrition language. Tonight you tell the PTA — parents who see one thing: less adult attention on their children in the library.","task":"Write 2-3 sentences for the PTA that state the cut plainly and what you're doing to protect the student experience.","tips":["Say the cut in parent terms: what changes in the library day-to-day.","No FTE-speak, no 'right-sizing' — words like that read as evasion.","Name the mitigation concretely, and only what you'll actually do."],"focus":["audience","clarity"]},
    {"id":"audience-edu-senior-20","level":"senior","profession":"education","title":"The dismissal change, for the vendor","scenario":"You're moving dismissal fifteen minutes earlier next month. The crossing-guard company and bus contractor need formal notice. Your draft, adapted from the parent letter, is full of family-facing warmth and missing the operational specifics a vendor needs.","task":"Write a 2-3 sentence vendor notice with the operational facts and the confirmation you need.","tips":["Vendors need effective date, new times, and affected posts or routes — nothing else.","Ask for written confirmation by a date.","Warm tone is fine; missing specifics are not."],"focus":["audience","precision"]},
    {"id":"audience-edu-senior-21","level":"senior","profession":"education","title":"Curriculum mapping, for the board's wallet","scenario":"You're asking the board to fund a curriculum-mapping year: teacher release time, consultant days, roughly $60,000. To you it's foundational; to a board member it sounds like paying teachers to fill in spreadsheets about what they already teach.","task":"Write 2-3 sentences that translate curriculum mapping into a problem-and-payoff the board recognizes.","tips":["Start from the visible problem: what students hit twice, what they never see.","Frame the $60,000 as fixing a specific, costly gap — give an example.","One sentence on how they'll know it worked."],"focus":["audience","impact"],"placeholder":"Right now a student can go through our middle school and never be taught fractions to mastery — two grades each assume the other covered it."},
    {"id":"audience-edu-senior-22","level":"senior","profession":"education","title":"The counselor's note, decoded","scenario":"A counselor drafted a letter to a family: \"Per the SST, your student has been referred for a 504 evaluation to assess eligibility for accommodations under Section 504.\" The family has never heard of any of it and may read \"evaluation\" as something being wrong with their child.","task":"Rewrite the letter's opening in 2-3 sentences a worried parent understands and isn't alarmed by.","tips":["Lead with the purpose in human terms: extra support so your child can do their best work.","Define the process by what the family will experience: a meeting, a plan.","Reassure precisely: this is common, voluntary, and parent-involved."],"focus":["audience","clarity"],"placeholder":"We'd like to look at whether some classroom supports — like extra time on tests — would help Maya do her best work."},
    {"id":"audience-edu-senior-23","level":"senior","profession":"education","title":"The gym closure, for the neighbors","scenario":"Your gym closes for a four-month renovation, which cancels the community pickleball league and weekend open hours that neighborhood residents — mostly retirees, not parents — rely on. Your draft notice is written like a school memo, full of school-calendar references.","task":"Write a 2-3 sentence notice for community users with the facts they need and an alternative.","tips":["Their stake is the program, not the school year — lead with closure dates and what's cancelled.","Offer the alternative arrangement concretely, or say honestly there isn't one yet.","These neighbors vote on your bonds; the tone should show you know they matter."],"focus":["audience","clarity"]},
    {"id":"audience-edu-senior-24","level":"senior","profession":"education","title":"One slide for cabinet","scenario":"The superintendent's cabinet reviews each school's improvement plan in ninety seconds — one slide each. Your current slide has eleven initiatives in eight-point font. Cabinet needs your priority, your evidence, and your ask.","task":"Write the three lines that belong on the slide: priority, evidence it's working or needed, and the ask.","tips":["One priority — choosing is the leadership act they're evaluating.","Evidence is a number, not an adjective.","If you have no ask, say 'no ask — on track.' That lands too."],"focus":["audience","concision"]},
    {"id":"audience-edu-senior-25","level":"senior","profession":"education","title":"AP expansion, for first-generation families","scenario":"You're expanding AP course access and want more first-generation college families to opt in. Your draft flyer assumes families know what AP is, what it costs, and why colleges care. The families you most want to reach know none of that.","task":"Write a 2-3 sentence invitation that assumes no prior knowledge of AP and answers the family's real questions.","tips":["Explain AP by its payoff: college credit earned in high school, for free.","Address the unspoken worry: my child might struggle — say what support exists.","Make the next step tiny and named: one meeting, one person to talk to."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-edu-senior-01","level":"senior","profession":"education","title":"The enrollment deck with no spine","scenario":"Your board presentation on enrollment decline has fourteen slides of data — birth rates, charter competition, housing turnover — but no governing idea. Board members will leave with fragments unless one sentence holds it together.","task":"Write the governing sentence and name the three buckets your slides will group under.","tips":["One sentence that carries the whole argument: what's happening, why, what you propose.","Three buckets maximum — force the merge.","Every slide should answer to a bucket or get cut."],"focus":["structure","clarity"],"placeholder":"We're losing about 25 students a year to two causes we can address — and the plan costs less than the revenue we're losing."},
    {"id":"structure-edu-senior-02","level":"senior","profession":"education","title":"SCQA for the staffing memo","scenario":"You're reallocating a teaching position from eighth grade to kindergarten next year based on cohort sizes. The memo to the district needs to land in one read. You know SCQA — situation, complication, question, answer — but your draft opens with the answer's mechanics.","task":"Write the four SCQA sentences for this memo, one each.","tips":["Situation: the stable fact everyone agrees on — cohort sizes are shifting.","Complication: what broke — kindergarten is over ratio, eighth grade under.","Question and answer should feel inevitable by the time they arrive."],"focus":["structure","clarity"]},
    {"id":"structure-edu-senior-03","level":"senior","profession":"education","title":"PREP for the bell-schedule question","scenario":"At tonight's board meeting someone will ask why you changed the bell schedule. You'll answer aloud, unscripted. PREP — point, reason, example, point — keeps a spoken answer from wandering.","task":"Write your PREP answer in four sentences, ready to say aloud.","tips":["Point first: we changed it to add 25 minutes of instruction.","One reason, one concrete example — a real class that gains time.","Restate the point in different words to close, then stop."],"focus":["structure","concision"],"placeholder":"We changed the schedule for one reason: it adds 25 minutes of daily instruction without lengthening the school day."},
    {"id":"structure-edu-senior-04","level":"senior","profession":"education","title":"Twelve tasks, three buckets","scenario":"Your school-improvement plan has become a list of twelve unranked action items: tutoring blocks, attendance calls, hallway supervision, data meetings, mentor pairings, family nights, and more. The district template asks for goals, but a list of twelve is a plan for nothing.","task":"Group the twelve items into three named buckets and write the one-line label for each.","tips":["Name buckets by outcome, not activity type: 'more students reading on level,' not 'literacy initiatives.'","If an item fits no bucket, question the item.","Three labels a teacher could recite from memory."],"focus":["structure","clarity"]},
    {"id":"structure-edu-senior-05","level":"senior","profession":"education","title":"The annual report skeleton","scenario":"Your annual report to the community historically follows the org chart: a section per department. Nobody reads it. This year you want it organized around what the community actually asks: are kids learning, are they safe, is the money well spent.","task":"Write the three section headers as full sentences that assert your answer, plus the opening line of the report.","tips":["Headers that assert ('Reading is up; math is our work') beat labels ('Academics').","The opening line should carry the year's whole story.","Structure around the reader's questions, not your departments."],"focus":["structure","audience"]},
    {"id":"structure-edu-senior-06","level":"senior","profession":"education","title":"The budget request pyramid","scenario":"Your budget request to the district asks for $240,000 across seven line items. As drafted it's a list with per-item justifications. The assistant superintendent will fund a coherent argument before she funds a shopping list.","task":"Write the governing idea and the three supporting claims that organize all seven items.","tips":["The governing idea says what the money buys as one outcome.","Each line item must ladder up to one of three claims.","If an item supports no claim, it's the first thing she'll cut — cut it yourself or find its argument."],"focus":["structure","impact"],"placeholder":"Everything in this request does one job: it keeps our intervention gains from evaporating when the grant ends."},
    {"id":"structure-edu-senior-07","level":"senior","profession":"education","title":"The boundary meeting agenda","scenario":"You're facilitating a community meeting on proposed attendance-boundary changes. Emotions will run high. A meeting with no visible structure becomes a grievance session; a structure announced up front gives anger a container.","task":"Write the 3-part agenda as you would announce it aloud in the first minute, one sentence per part.","tips":["Announce the shape: what we'll cover, in what order, when you get to speak.","Put 'what is and isn't decided yet' as an explicit early part.","Say how input will be used — structure without that is theater."],"focus":["structure","audience"]},
    {"id":"structure-edu-senior-08","level":"senior","profession":"education","title":"The self-study summary","scenario":"Your accreditation self-study runs 90 pages across dozens of standards. The visiting team chair reads the executive summary first and forms the impression everything else confirms. Your draft summary is a compressed table of contents.","task":"Write the governing sentence of the executive summary and the three findings it organizes.","tips":["Lead with your honest overall assessment — strong, growing, or uneven.","Three findings: the best thing, the real gap, the trajectory.","A summary that admits the gap earns belief in the strengths."],"focus":["structure","precision"]},
    {"id":"structure-edu-senior-09","level":"senior","profession":"education","title":"The survey-results staff meeting","scenario":"Staff climate-survey results are back and they sting: 41% feel decisions are made without input. You're presenting the results at Monday's staff meeting. Data dumped without structure will read as either spin or self-flagellation.","task":"Outline your talk in three labeled moves, with one sentence of content for each.","tips":["A clean spine: what you said, what I heard, what changes.","Put the worst number in move one, verbatim — hiding it costs more.","Move three must contain one dated commitment, or the talk makes things worse."],"focus":["structure","impact"],"placeholder":"Here's what you told us — including the number that stung most: 41% of you feel decisions happen without your input."},
    {"id":"structure-edu-senior-10","level":"senior","profession":"education","title":"SCQA for the grant opener","scenario":"You're writing the opening paragraph of a state grant application for expanded pre-K. Reviewers score dozens of these; most openings describe the applicant. SCQA turns your opening into an argument instead of a bio.","task":"Write the grant's opening paragraph as four SCQA sentences.","tips":["Situation: the community fact — how many four-year-olds, how few seats.","Complication: what it costs them — kindergartners arriving two years behind.","The answer sentence is your program in one line with the outcome named."],"focus":["structure","impact"]},
    {"id":"structure-edu-senior-11","level":"senior","profession":"education","title":"PREP for the safety question","scenario":"A local TV reporter will ask you on camera: \"Is this school safe?\" A rambling answer gets edited into whatever clip they need. A PREP answer is hard to cut misleadingly because every sentence carries the same message.","task":"Write your four-sentence PREP answer, ready for camera.","tips":["Point: yes, and here is what that rests on — say it whole.","Reason and example must be checkable facts, not reassurance.","Closing restatement should survive as a standalone clip."],"focus":["structure","precision"]},
    {"id":"structure-edu-senior-12","level":"senior","profession":"education","title":"The discipline report's shape","scenario":"Your board wants the annual discipline report. The raw material: suspension counts, incident categories, demographic breakdowns, the new restorative program's first-year data. Presented as tables in sequence, it invites twenty scattered questions.","task":"Write the governing sentence and three section claims that give the report an argument.","tips":["Decide first what the data honestly says overall — that's your governing sentence.","Sections as claims: 'Incidents fell; disparities didn't' tells the truth and organizes it.","Order sections so the hardest finding isn't buried last — that placement reads as hiding."],"focus":["structure","precision"],"placeholder":"The headline is mixed and I'll say it plainly: total incidents are down 22%, but the disparity in who gets suspended has not moved."},
    {"id":"structure-edu-senior-13","level":"senior","profession":"education","title":"One letter for forty emails","scenario":"Your new grading policy generated forty parent emails with overlapping objections. You're writing one public letter instead of forty replies. Answering complaints in the order received produces a rebuttal list, not a letter.","task":"Group the objections into three themes and write the one-sentence response header for each.","tips":["Find the three real questions under the forty emails.","Answer themes, not individuals — no one should find their email quoted.","Lead the letter with what you've heard, in the parents' own framing."],"focus":["structure","audience"]},
    {"id":"structure-edu-senior-14","level":"senior","profession":"education","title":"The caseload pyramid","scenario":"Your counselor-caseload proposal has a mountain of support: ratios, wait times, crisis-referral counts, comparison districts, a student story. Piled up, they blur. A pyramid — one claim, three legs — makes them land.","task":"Write the apex claim and assign your evidence to three supporting legs, one line each.","tips":["The apex is the decision sentence: fund one counselor FTE.","Legs might be: need (ratios), consequence (wait times, crises), feasibility (cost vs. comparisons).","The student story belongs inside a leg as its illustration, not floating alone."],"focus":["structure","impact"]},
    {"id":"structure-edu-senior-15","level":"senior","profession":"education","title":"Listening-session themes","scenario":"You ran four community listening sessions on the school's five-year direction and have nine pages of sticky-note comments: bus times, bullying, more arts, teacher turnover, homework load, building temperature. You promised to report back what you heard.","task":"Write the 3-4 theme headers you'd report back, each with one verbatim-style example under it.","tips":["Themes should cover most comments without a 'miscellaneous' dumping ground.","Keep one real, specific comment per theme — it proves you listened.","Report the uncomfortable theme too; the room remembers what it said."],"focus":["structure","audience"]},
    {"id":"structure-edu-senior-16","level":"senior","profession":"education","title":"The induction overview","scenario":"The board asked how you onboard new teachers, prompted by turnover concerns. You could list every activity: mentor assignment, release days, observation cycles, check-ins. A list proves activity; a structure proves design.","task":"Present the induction program as one governing idea with three phases, one sentence each.","tips":["The governing idea names the outcome: new teachers who stay and grow.","Phases with time boundaries read as design: before day one, first semester, first year.","Attach one number — retention of mentored vs. unmentored hires if you have it."],"focus":["structure","clarity"]},
    {"id":"structure-edu-senior-17","level":"senior","profession":"education","title":"SCQA for the interventionist","scenario":"You want the district to fund a reading interventionist. Your draft memo leads with the job description. The assistant superintendent needs to feel the gap before she'll read the solution.","task":"Write the memo's opening as four SCQA sentences ending in the ask.","tips":["Situation: your reading data as it stands.","Complication: the 38 students below benchmark whom no current role serves.","The question ('who catches them?') makes the ask feel like the only answer."],"focus":["structure","impact"],"placeholder":"Our core reading instruction is working for most students: 74% are at benchmark. But 38 children are more than a year behind, and no role in the building is staffed to catch them."},
    {"id":"structure-edu-senior-18","level":"senior","profession":"education","title":"Eleven bullets, three buckets","scenario":"Your monthly principal's report has grown to eleven bullets of unranked news: a robotics win, a staffing change, test dates, a facilities update, a partnership, and more. The board skims it. Eleven bullets means no message.","task":"Sort the eleven into three labeled buckets and write the one-sentence headline for the whole report.","tips":["Buckets like 'students, staff, building' give readers a map.","The headline sentence is what a board member repeats at dinner.","Anything that fits no bucket and carries no decision — cut it."],"focus":["structure","concision"]},
    {"id":"structure-edu-senior-19","level":"senior","profession":"education","title":"PREP at the bargaining table","scenario":"In tomorrow's negotiation session the union will ask why you're proposing to change the supervision-duty roster. Your answer, spoken across the table, sets the tone for the session. Wandering reads as hiding something.","task":"Write your four-sentence PREP answer for the table.","tips":["Point: the change equalizes duty load — say it without preamble.","Your example should be a real inequity both sides know about.","No editorializing about the old system's defenders; facts only."],"focus":["structure","audience"]},
    {"id":"structure-edu-senior-20","level":"senior","profession":"education","title":"The flood-recovery update","scenario":"Two weeks after the burst pipe flooded six classrooms, families need an update. You have news across repair timelines, relocated classes, air-quality testing, and insurance. A chronological dump reads as chaos; parents need it organized by their questions.","task":"Write the update's three section headers as questions parents are asking, with a one-line answer under each.","tips":["Their questions: is my child's classroom safe, when is this over, what changes meanwhile.","Answer each header's question in its first line, then detail.","Air-quality results need a number and a source, not 'testing continues.'"],"focus":["structure","audience"],"placeholder":"Is the building safe? Yes — independent air-quality tests on Tuesday came back clear, and the results are posted on our website."},
    {"id":"structure-edu-senior-21","level":"senior","profession":"education","title":"The later-start argument","scenario":"You're building the case to move high-school start time from 7:25 to 8:15. The evidence sprawls: sleep research, attendance data, athletic conflicts, bus-tier costs, peer districts. Opponents have one crisp objection — buses — and crisp beats sprawling.","task":"Structure your case as one governing sentence and three supports, with the bus problem placed deliberately.","tips":["Don't hide the bus cost — make 'and here's how we pay for it' a named support.","Governing sentence pairs benefit and feasibility in one breath.","Three supports; the research citations live inside one of them."],"focus":["structure","impact"]},
    {"id":"structure-edu-senior-22","level":"senior","profession":"education","title":"The program-closure memo","scenario":"You're recommending the district close your school's automotive-tech program: enrollment fell to nine students and the equipment needs $120,000 in updates. The memo will be read by people who fought to create the program. Structure is what keeps it from reading as a hit job.","task":"Write the memo's governing sentence and three sections: the case, what was tried, and the transition plan.","tips":["The governing sentence owns the recommendation and its hardest fact together.","'What we tried first' is the section that earns the right to recommend closure.","The transition section must answer for the nine current students by name-level specificity."],"focus":["structure","clarity"]},
    {"id":"structure-edu-senior-23","level":"senior","profession":"education","title":"The capital-request grouping","scenario":"Facilities walked the building with you and produced 23 needs: roof sections, HVAC units, door hardware, asphalt, lighting, plumbing. The district's capital committee funds narratives, not lists. Your job is to turn 23 items into an argument.","task":"Group the 23 items into three funding buckets with names that carry urgency, one line each.","tips":["Group by consequence: safety and security, keep-the-building-running, learning environment.","Sequence buckets by what happens if unfunded.","Each bucket gets one total dollar figure — committees think in three numbers, not 23."],"focus":["structure","impact"]},
    {"id":"structure-edu-senior-24","level":"senior","profession":"education","title":"SCQA for the absenteeism plan","scenario":"The superintendent asked for your chronic-absenteeism plan in a one-page memo. Your draft starts with the plan's activities. She needs to see the problem's shape before the plan reads as proportionate.","task":"Write the one-pager's opening as four SCQA sentences.","tips":["Situation: attendance overall, honestly stated.","Complication: the 18% who miss a month of school and what it predicts.","Answer previews the plan's three moves in one sentence — details below."],"focus":["structure","concision"],"placeholder":"Most of our students attend regularly — average daily attendance is 93%. But 118 students, nearly one in five, will miss more than three weeks of school this year."},
    {"id":"structure-edu-senior-25","level":"senior","profession":"education","title":"Five minutes at the hearing","scenario":"The state board is holding a hearing on proposed graduation-requirement changes, and you have exactly five minutes of testimony. You have twenty things to say about how the changes hit schools like yours. Five minutes rewards one idea, structured.","task":"Write your testimony's spine: opening claim, three points as single sentences, and the closing sentence.","tips":["One claim the panel can vote on in their heads.","Three points, each anchored to your school's real numbers.","The closing sentence is the claim again, sharpened — write it first."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-edu-senior-01","level":"senior","profession":"education","title":"The picture-day paragraph","scenario":"Your newsletter draft spends 190 words on picture day: the history of the vendor relationship, the ordering portal, retake policies, a reminder about smiles. Families need about 40 words of it.","task":"Write the picture-day item in 40 words or fewer without losing any needed fact.","tips":["Keep only what a parent must do: date, dress, how to order.","Cut everything the portal explains again anyway.","One sentence of warmth maximum — the date is the kindness."],"focus":["concision","audience"]},
    {"id":"concise-edu-senior-02","level":"senior","profession":"education","title":"The hedge-filled staffing memo","scenario":"Your memo to the superintendent reads: \"I think we should perhaps consider the possibility of potentially restructuring the front-office staffing model at some point in the near future, if that seems reasonable.\" You actually mean: cut one clerk position and add a family liaison this summer.","task":"Rewrite the sentence to say exactly what you mean, hedges removed.","tips":["Every 'perhaps,' 'consider,' and 'possibility' transfers your decision to the reader.","Keep one honest qualifier only if the uncertainty is real — name it precisely.","A senior leader's hedges read as either fear or evasion."],"focus":["concision","clarity"],"placeholder":"I recommend we cut one front-office clerk position and add a family liaison, effective this summer."},
    {"id":"concise-edu-senior-03","level":"senior","profession":"education","title":"The nominalization audit","scenario":"Your improvement-plan draft says: \"The implementation of the utilization of formative assessment data will result in the facilitation of the identification of students in need of intervention.\" Buried in there is a simple sentence about teachers and kids.","task":"Rewrite it as one plain sentence with people doing verbs.","tips":["Find the actor and the action: teachers use data, and they find kids who need help.","Every '-tion of the -tion' hides a verb — dig it out.","If a state template forces the jargon, write the plain version first and translate up."],"focus":["concision","clarity"],"placeholder":"Teachers will review quiz data every two weeks and flag students who need extra help."},
    {"id":"concise-edu-senior-04","level":"senior","profession":"education","title":"The throat-clearing board remarks","scenario":"Your board remarks open: \"Before I begin, I'd like to take a moment to say a few words about the process that brought us here tonight, and to thank everyone whose hard work made this possible, of which there are too many to name.\" Fifty words; zero content.","task":"Cut the opening so your first sentence carries actual content, keeping thanks to one clause if at all.","tips":["Meta-commentary ('before I begin,' 'I'd like to say') announces speech instead of speaking.","Gratitude survives compression: 'thanks to the committee's work, here's the plan.'","Your first ten words are the most-attended of the night — spend them on the point."],"focus":["concision","impact"]},
    {"id":"concise-edu-senior-05","level":"senior","profession":"education","title":"The redundant-pairs letter","scenario":"Your draft policy letter to families is padded with pairs: \"each and every student,\" \"first and foremost,\" \"hopes and dreams,\" \"null and void,\" \"basic and fundamental.\" It sounds ceremonial and reads slow.","task":"Rewrite two of its sentences keeping one word from each pair.","tips":["Pick the stronger word of each pair; delete its twin.","Ceremony in policy letters buys no trust — clarity does.","Read aloud after cutting: the rhythm improves, which is the tell."],"focus":["concision","clarity"]},
    {"id":"concise-edu-senior-06","level":"senior","profession":"education","title":"The copier email, halved","scenario":"Your draft email about the new copier procedures runs 160 words: an apology for the old copier, an explanation of the lease, the new code system, a request for patience, and a closing about teamwork. Teachers will skim it in four seconds.","task":"Rewrite the email in under 60 words with every operative fact intact.","tips":["Operative facts: new code, where to get yours, what changed, who to ask.","The lease story and the teamwork closing serve you, not the reader.","Subject line does half the work: 'New copier codes — get yours by Friday.'"],"focus":["concision","clarity"]},
    {"id":"concise-edu-senior-07","level":"senior","profession":"education","title":"The attendance letter diet","scenario":"Your standard attendance-concern letter to families runs three paragraphs: legal citations, district policy history, a paragraph of encouragement, then the actual concern. Families report finding it confusing — several thought it was junk mail.","task":"Rewrite the letter's substance in four sentences: the fact, why it matters, the ask, the offer of help.","tips":["Lead with the child's actual number of absences — the specific fact, not 'a concern.'","One sentence on why it matters; skip the statute numbers.","End with a named person and phone number, not 'contact the office.'"],"focus":["concision","audience"],"placeholder":"Jordan has missed 12 days of school this year — that's more than two full weeks of instruction."},
    {"id":"concise-edu-senior-08","level":"senior","profession":"education","title":"The recommendation-letter filler","scenario":"You're writing a reference for a departing assistant principal. Your draft is full of filler: \"It is with great pleasure that I write,\" \"in my professional opinion,\" \"it goes without saying,\" \"words cannot express.\" The reader wants evidence, not upholstery.","task":"Rewrite the opening two sentences so they carry a specific, verifiable achievement instead of filler.","tips":["Open with the strongest fact you'd stake your name on.","'In my opinion' is implied by your signature — cut it.","One concrete scene outweighs three paragraphs of adjectives."],"focus":["concision","precision"]},
    {"id":"concise-edu-senior-09","level":"senior","profession":"education","title":"The rambling incident report","scenario":"An assistant principal's incident report on a cafeteria altercation runs 600 words of unsorted narrative: who was standing where, prior history, weather, three witness fragments, and — somewhere — what actually happened. Legal may read this someday.","task":"Write the report's first three sentences: what happened, who was involved, what was done.","tips":["Facts in past tense, actors named, times stated.","No characterizations ('aggressive kid') — only observed behavior.","Detail belongs in the body; the opening must stand alone if quoted."],"focus":["concision","precision"]},
    {"id":"concise-edu-senior-10","level":"senior","profession":"education","title":"The 300-character alert","scenario":"A power outage is closing school two hours early today. The emergency text system truncates at 300 characters, and parents will read it on a lock screen while working. Your draft is 500 characters of context and apology.","task":"Write the alert in under 300 characters with every fact a parent needs to act.","tips":["Facts only: what, when, buses, pickup, where to check for updates.","Cut the apology and the cause — the website can carry those.","Read it as a parent at work: can they act on it in ten seconds?"],"focus":["concision","clarity"],"placeholder":"POWER OUTAGE: School closes at 1:00 today. Buses run 2 hrs early. Walkers dismissed 1:00. Aftercare cancelled."},
    {"id":"concise-edu-senior-11","level":"senior","profession":"education","title":"The grant abstract, uncluttered","scenario":"Your grant abstract's first sentence: \"In today's rapidly changing educational landscape, it has become increasingly clear that schools such as ours must seek innovative solutions to the multifaceted challenges facing our diverse learners.\" Thirty-five words; the reviewer has learned nothing.","task":"Write a replacement first sentence that states what you'll do and for whom, in under 20 words.","tips":["Cut every phrase that could open any grant from any school — that's the test.","Name the number of students and the specific change.","'Innovative' is a claim; the program description should prove it instead."],"focus":["concision","precision"],"placeholder":"We will provide daily 30-minute reading intervention to the 38 third-graders furthest behind."},
    {"id":"concise-edu-senior-12","level":"senior","profession":"education","title":"The compliance response, halved","scenario":"Your draft response to a district records-compliance query runs 400 words, restating their question, summarizing the regulation, describing your general philosophy of record-keeping, and finally answering. The compliance officer processes forty of these a week.","task":"Rewrite the response in under 100 words: the direct answer, the evidence, the one open item.","tips":["Answer in sentence one; she can see her own question above your reply.","Evidence as a list, not prose.","Flag anything incomplete honestly — burying it in length reads worse later."],"focus":["concision","structure"]},
    {"id":"concise-edu-senior-13","level":"senior","profession":"education","title":"Three lines for the radio","scenario":"You have a 90-second local-radio segment about the new career-tech wing. Your communications draft has six talking points with sub-bullets. On radio you'll get through three short lines, interrupted.","task":"Write the three lines — each under 15 words, each able to stand alone.","tips":["Each line must survive being the only one that airs.","Numbers stick on radio: 200 students, 6 trades, opens August.","Practice the cut: if you had five seconds, which line? That's line one."],"focus":["concision","impact"]},
    {"id":"concise-edu-senior-14","level":"senior","profession":"education","title":"The union letter warm-up","scenario":"Your letter to the union president opens: \"As you know, we have been engaged in ongoing discussions regarding the matters previously raised in our earlier correspondence, and as per our conversation last week...\" Two lines of referencing, no content.","task":"Rewrite the opening so sentence one states the letter's purpose outright.","tips":["'As you know' introduces things the reader knows — delete and start.","One reference clause is plenty: 'Following Tuesday's session, ...'","In labor relations, padding reads as maneuvering; plainness reads as good faith."],"focus":["concision","clarity"],"placeholder":"Following Tuesday's session, here is our revised proposal on the supervision-duty schedule."},
    {"id":"concise-edu-senior-15","level":"senior","profession":"education","title":"The bloated job posting","scenario":"Your assistant-principal posting runs 700 words: a paragraph of mission statement, twelve responsibilities, nine qualifications, and boilerplate. Strong candidates skim postings the way you skim résumés. The three things that make this job distinct are buried.","task":"Write the posting's first three sentences so a strong candidate knows why this job, this school.","tips":["Lead with what's distinct: the school's trajectory, the mandate, the growth path.","Twelve responsibilities signal 'we haven't decided what this job is.' Pick four.","Boilerplate below the fold; the hook above it."],"focus":["concision","audience"]},
    {"id":"concise-edu-senior-16","level":"senior","profession":"education","title":"Ten slides to one sentence","scenario":"Your budget presentation is ten slides. The superintendent just texted: board time is cut, you get 60 seconds and one slide. Whatever you say now IS the presentation.","task":"Write the one sentence that carries the entire budget request.","tips":["The sentence needs the ask, the amount, and the consequence funded or unfunded.","If two clauses fight for the sentence, the one with a number wins.","This sentence existed all along — the ten slides were hiding it."],"focus":["concision","impact"],"placeholder":"For $240,000 — 1.1% of our budget — we keep the reading gains we just spent three years earning."},
    {"id":"concise-edu-senior-17","level":"senior","profession":"education","title":"The agenda cover memo","scenario":"Your cover memo for the board packet summarizes each of nine agenda items in a paragraph. Board members get the packet Friday night; most read the cover memo only. Nine paragraphs guarantees they read none well.","task":"Rewrite the cover memo as nine single lines, flagging the two items needing real attention.","tips":["One line per item: what it is and what the board must do (vote, discuss, note).","Flag the two heavy items visibly and give them each one extra sentence.","The memo's job is triage, not summary."],"focus":["concision","structure"]},
    {"id":"concise-edu-senior-18","level":"senior","profession":"education","title":"The suspension letter, de-bureaucratized","scenario":"Your template suspension letter reads: \"Pursuant to Board Policy 5114, a determination has been made that a violation of the student code of conduct has occurred, resulting in the imposition of a period of suspension.\" A parent reads this and learns almost nothing.","task":"Rewrite the letter's opening in two sentences of plain active language: what happened and what has been decided.","tips":["Active voice with actors: your child did X; the school has decided Y.","Keep the policy citation — one clause at the end, not the spine.","Plain language here is legally safer, not riskier: it proves the parent was actually informed."],"focus":["concision","clarity"],"placeholder":"On Tuesday, Marcus was involved in a fight in the west hallway. He is suspended for two school days, Thursday and Friday, under Board Policy 5114."},
    {"id":"concise-edu-senior-19","level":"senior","profession":"education","title":"The two-sentence apology","scenario":"A miscommunication sent 30 kindergartners home on the wrong buses for twenty frightening minutes. All are safe. Your five-sentence draft apology circles through explanations before apologizing. Over-explained apologies read as self-defense.","task":"Write the apology in two sentences: the plain apology, then the one fix.","tips":["Sentence one owns it without 'we regret any confusion' distancing.","Sentence two is the concrete fix, not a promise to 'review procedures.'","Cut every clause that explains why it wasn't quite your fault."],"focus":["concision","impact"]},
    {"id":"concise-edu-senior-20","level":"senior","profession":"education","title":"The marquee problem","scenario":"The school marquee fits 40 characters per line, two lines. You need it to announce kindergarten registration opening March 1 with the website. Your communications draft is a paragraph.","task":"Write the two marquee lines, 40 characters each maximum.","tips":["Verbs and dates; drop articles ruthlessly.","The website is the second line's whole job.","If a passing driver gets one fact, it's the date — put it first."],"focus":["concision","clarity"]},
    {"id":"concise-edu-senior-21","level":"senior","profession":"education","title":"The hedged conversation opener","scenario":"You're opening a performance conversation with a teacher whose classroom has serious management problems. Your planned opener: \"So I just wanted to touch base and kind of check in about how things have maybe been going, classroom-wise, if that's okay.\" The hedges promise a conversation you don't intend to have.","task":"Write the honest one-sentence opener that names the topic without cruelty or hedging.","tips":["Name the subject in the first sentence: this meeting is about classroom management.","Hedged openers feel kind but are cruel — the teacher prepares for the wrong meeting.","Calm and direct: no 'just,' no 'kind of,' no fake casualness."],"focus":["concision","clarity"],"placeholder":"I want to talk about what I saw in your classroom on Tuesday and Thursday, and what needs to change."},
    {"id":"concise-edu-senior-22","level":"senior","profession":"education","title":"The event recap, compressed","scenario":"A staff member drafted 400 words on the science fair for the newsletter: setup logistics, a thank-you list of nineteen names, judging criteria, and — in the middle — the actual news: 80 projects, three state qualifiers. You have a 60-word slot.","task":"Write the 60-word version that leads with the news.","tips":["The news: 80 projects, 3 state qualifiers, names of the three.","Thank volunteers as a group with one named organizer.","Logistics interested nobody who wasn't there."],"focus":["concision","impact"]},
    {"id":"concise-edu-senior-23","level":"senior","profession":"education","title":"Welcome remarks, halved","scenario":"Your new-family welcome-night remarks run ten minutes in draft: school history, your philosophy, staff introductions, program overviews. Half the audience has a toddler on their lap. Five minutes is the ceiling and three is better.","task":"Cut the draft's plan to three moves you can deliver in three minutes — name them and write the opening line.","tips":["Three moves: what your child gets here, the one thing to do this week, how to reach a human.","History and philosophy are the website's job.","The opening line should make a tired parent glad they came."],"focus":["concision","audience"]},
    {"id":"concise-edu-senior-24","level":"senior","profession":"education","title":"The print-shop request","scenario":"Your email to the district print shop runs 120 words explaining the event, the audience, and the design's history before stating what you need: 400 tri-fold programs, color, by Friday the 14th. Print shops fill orders, not read essays.","task":"Rewrite the request in two sentences with every specification present.","tips":["Specs first: quantity, format, color, paper, deadline, delivery point.","Attach the file and say so; the design's history is irrelevant.","One question mark maximum — and only if something genuinely needs their call."],"focus":["concision","precision"]},
    {"id":"concise-edu-senior-25","level":"senior","profession":"education","title":"The drill instructions, tightened","scenario":"Your evacuation-drill instructions to staff run a full page. Buried in the prose: three changes from last year. In a real emergency nobody re-reads a page; they remember what was short enough to remember.","task":"Rewrite the instructions as a headline plus the three changes, under 60 words total.","tips":["Lead with 'three things changed' — that's the whole reason to read.","One line per change: old way, new way.","The unchanged procedure needs a link, not a reprint."],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-edu-senior-01","level":"senior","profession":"education","title":"Replace 'significant gains' with the number","scenario":"Your board slide says third-grade reading \"improved significantly\" this year. Board members allocate money on numbers, not adjectives, and you have the benchmark data behind the claim.","task":"Rewrite the claim with the specific figures and a comparison that gives them scale.","tips":["'Significantly' is what you write before you've done the arithmetic — do it.","Anchor the number: points gained, versus last year, versus the district.","A number the board can verify beats an adjective they have to trust."],"focus":["precision","impact"],"placeholder":"Third-grade reading proficiency rose from 54% to 63% — nine points in one year, our largest gain since 2019."},
    {"id":"precision-edu-senior-02","level":"senior","profession":"education","title":"'Many parents' becomes a count","scenario":"Your memo opposing the earlier start time says \"many parents have expressed concern.\" The first board question will be: how many, out of how many? You ran a survey — use it.","task":"Rewrite the sentence so the claim carries its own evidence.","tips":["Give the count and the base: 412 of 640 responding families.","Name the instrument — survey, forum sign-ins — so it's checkable.","If the number is small, say it plainly; inflating it costs you the room."],"focus":["precision","clarity"],"placeholder":"In last month's survey, 412 of 640 responding families — 64% — opposed the 7:30 start."},
    {"id":"precision-edu-senior-03","level":"senior","profession":"education","title":"What / So What / Now What on absenteeism","scenario":"Your finding stops at the fact: \"chronic absenteeism reached 18% this year.\" The board needs the consequence in outcomes and dollars, and the action you propose. Complete the chain.","task":"Write the three-part finding — What, So What, Now What — one sentence each.","tips":["'So what' converts the rate into failed courses and lost enrollment revenue.","'Now what' is the specific intervention with a cost and a start date.","Each sentence should make the next one feel inevitable."],"focus":["structure","precision"],"placeholder":"Chronic absenteeism hit 18% — 112 students. Those students fail courses at four times the rate of peers, and attendance-linked funding drops with them. I'm proposing —"},
    {"id":"precision-edu-senior-04","level":"senior","profession":"education","title":"The tax claim a homeowner can check","scenario":"Your referendum flyer says the bond has a \"modest impact on property taxes.\" Every skeptical taxpayer will do the math on their own house — do it for them, accurately.","task":"Rewrite the claim with the actual dollar impact on a median home.","tips":["'Modest' invites suspicion; a checkable number builds trust.","Use the median home value and the monthly figure — that's how people budget.","State the term: how much, for how many years."],"focus":["precision","audience"],"placeholder":"For the median $280,000 home, the bond adds $11 a month — $132 a year — for 20 years."},
    {"id":"precision-edu-senior-05","level":"senior","profession":"education","title":"Date the 'soon'","scenario":"Your facilities update tells the board the HVAC replacement will happen \"soon\" and classroom renovations will follow \"in the near term.\" The board approves budgets by fiscal year, not by vibes.","task":"Rewrite the timeline with dates and phases the board can hold you to.","tips":["'Soon' means nothing to a capital plan — give months and phases.","Sequence it: design, bid, construction, occupancy.","A date you might miss beats a vagueness nobody can plan around."],"focus":["precision","clarity"],"placeholder":"HVAC design finishes in March, bids close in May, and installation runs June through August —"},
    {"id":"precision-edu-senior-06","level":"senior","profession":"education","title":"Quantify 'morale is low'","scenario":"Your staffing memo to the superintendent says \"teacher morale is low and people are burning out.\" It's true, but unactionable. You have climate-survey results and resignation data. Convert the impression into evidence.","task":"Rewrite the finding with the numbers that make it undeniable.","tips":["Pick the number tied to a cost: resignations, not just sentiment scores.","Pair one hard statistic with one line of qualitative color.","A feeling can be waved away; a trend line can't."],"focus":["precision","impact"],"placeholder":"Mid-year resignations doubled — 9 this year against 4 last — and only 41% of staff say they plan to be here in three years, down from 68%."},
    {"id":"precision-edu-senior-07","level":"senior","profession":"education","title":"One insight from the benchmark table","scenario":"Your board packet includes a dense table of benchmark scores by grade and subgroup. Buried in it is the story: every grade grew except sixth-grade math, which dropped eight points. The board will stare at the table and ask 'so what?'.","task":"Write the one-sentence insight the table proves, and name the cells that prove it.","tips":["A table shows data; your sentence states what it means.","The insight has a direction: up, down, concentrated, at risk.","If the board has to find the point themselves, the slide failed."],"focus":["precision","clarity"],"placeholder":"Every grade grew this year except one: sixth-grade math fell eight points, and that's where I'm directing intervention money."},
    {"id":"precision-edu-senior-08","level":"senior","profession":"education","title":"Pass the skeptic test on class size","scenario":"You're asking the board to fund smaller kindergarten classes, claiming it will raise reading outcomes. One board member reads research for sport and will ask: says who? Arm the claim before she fires.","task":"Rewrite the claim so the evidence and its source are visible in the sentence.","tips":["A claim without a basis is an opinion; name the study or the local data.","Cite the finding's size, not just its existence.","Write it so the skeptic's next question is already answered."],"focus":["precision","impact"],"placeholder":"The Tennessee STAR study — the largest class-size experiment run — found K-3 classes under 18 raised reading scores by —"},
    {"id":"precision-edu-senior-09","level":"senior","profession":"education","title":"'A small number of students'","scenario":"A reporter asks how many students were involved in the vaping incidents behind this week's suspensions. Your drafted line says \"a small number of students.\" The reporter will get the number anyway — from someone less careful.","task":"Write the sentence that gives the number, or states precisely why you won't.","tips":["If you can say it, say it: seven students, three suspensions.","If privacy law prevents it, name the law — that's a reason, not a dodge.","'A small number' reads as hiding; precision reads as control."],"focus":["precision","audience"],"placeholder":"Seven students were involved; three received suspensions under the district's tobacco policy."},
    {"id":"precision-edu-senior-10","level":"senior","profession":"education","title":"Graduation rate, defined","scenario":"Your annual report claims a 94% graduation rate. A board member notes the state site shows 89%. Both are real — different cohort definitions. Your credibility depends on stating which number you're using and why.","task":"Write the sentence that states the rate with its definition attached.","tips":["Name the cohort: four-year adjusted, five-year, or completers.","Reconcile the two numbers in one clause before someone else does.","The precise, smaller number you explain beats the bigger one you can't."],"focus":["precision","clarity"],"placeholder":"Our four-year adjusted cohort rate is 89%; including fifth-year completers it reaches 94% —"},
    {"id":"precision-edu-senior-11","level":"senior","profession":"education","title":"The security upgrade, specified","scenario":"After a community scare, your letter home says the school has \"enhanced security measures.\" Parents hear that phrase from every institution that's done nothing. Specifics reassure; vagueness alarms.","task":"Rewrite the sentence with 2-3 concrete, verifiable changes — without publishing a vulnerability map.","tips":["Name what a parent can see: single-entry vestibule, new visitor screening, added SRO hours.","Specific and verifiable is the whole game — 'enhanced' is neither.","You can be concrete about what changed without detailing what remains."],"focus":["precision","audience"],"placeholder":"Since January we've installed a single-point-of-entry vestibule, moved to ID-scan visitor screening, and doubled our resource officer's on-site hours."},
    {"id":"precision-edu-senior-12","level":"senior","profession":"education","title":"'Attendance is improving'","scenario":"Your principal's report says attendance is \"improving.\" From what, to what, since when? Without a baseline the claim is decoration — and this board remembers last year's numbers better than you'd like.","task":"Rewrite the claim with the baseline, the current figure, and the period.","tips":["Improvement is a delta: two numbers and a time frame.","Choose the honest comparison — same semester last year, not the flu week.","Small real gains stated precisely outperform big vague ones."],"focus":["precision","concision"],"placeholder":"Daily attendance is 93.1% this semester, up from 91.4% the same period last year."},
    {"id":"precision-edu-senior-13","level":"senior","profession":"education","title":"Comparable salaries at the table","scenario":"In negotiations, the union states the district pays \"well below market.\" You've pulled the actual comparables. Your response has to be precise enough to survive their fact-check, or you lose the table.","task":"Write the 1-2 sentence counter that states the comparison — which districts, which step, which year.","tips":["Define the comparison set before you state the result.","Compare like to like: same step, same lane, same year.","If the data partly supports them, concede that part — precision includes what hurts."],"focus":["precision","audience"],"placeholder":"Against the eight districts in our athletic conference, our BA step 5 salary ranks third — $1,200 above the median — though our top step trails by —"},
    {"id":"precision-edu-senior-14","level":"senior","profession":"education","title":"The projection with an honest range","scenario":"The board wants your five-year enrollment number. Your model says roughly 540, but housing turnover could swing it 30 either way. False precision will be quoted back at you in year three.","task":"Write the projection sentence with the range and the driver of the uncertainty.","tips":["State the central estimate and the band: 540, plus or minus 30.","Name what moves the number — the Maple Street development, charter capacity.","A range you explain reads as rigor, not hedging."],"focus":["precision","clarity"],"placeholder":"We project 540 students in five years, with a realistic range of 510 to 570 depending on whether the Maple Street development fills —"},
    {"id":"precision-edu-senior-15","level":"senior","profession":"education","title":"Outcomes, not activities","scenario":"Your literacy-grant report proudly counts activities: 14 workshops held, 60 teachers trained. The funder's board wants outcomes: did children read better? You have the assessment data — lead with it.","task":"Rewrite the report's key sentence around a student outcome, with activities as support.","tips":["Workshops are inputs; reading growth is the outcome the money bought.","One outcome number, then the activity count that produced it.","Funders renew results, not effort."],"focus":["precision","impact"],"placeholder":"Students in participating classrooms gained 1.4 years of reading growth in one year — driven by the 60 teachers trained across 14 workshops."},
    {"id":"precision-edu-senior-16","level":"senior","profession":"education","title":"Name the programs the cut hits","scenario":"Your budget testimony says the proposed cut \"will hurt programs students love.\" The council hears that from everyone. Name the programs, the students, and the numbers, or the sentence evaporates on contact.","task":"Rewrite the claim with the specific programs and enrollment counts affected.","tips":["'Programs' is an abstraction; 'orchestra, robotics, and JV soccer' is a constituency.","Attach the headcount: 240 students lose their activity.","Specificity converts sympathy into pressure."],"focus":["precision","impact"],"placeholder":"This cut eliminates orchestra, robotics, and two JV teams — 240 students, one in three of our middle schoolers, lose their program."},
    {"id":"precision-edu-senior-17","level":"senior","profession":"education","title":"'Well below the state average' — show both numbers","scenario":"Your equity report says the school's suspension rate is \"well below the state average.\" A journalist covering discipline disparities will ask for both figures and the subgroup breakdown. Put the numbers in the sentence first.","task":"Rewrite the claim with both rates — and flag the subgroup gap honestly if one exists.","tips":["A comparison needs both sides: our 3.1% against the state's 5.4%.","If a subgroup gap exists, surface it yourself with the plan attached.","The number you disclose is context; the number they dig up is a story."],"focus":["precision","audience"],"placeholder":"Our suspension rate is 3.1% against a state average of 5.4% — though I want the board to see the gap inside that number:"},
    {"id":"precision-edu-senior-18","level":"senior","profession":"education","title":"Round honestly","scenario":"Your packet rounds attendance to \"roughly 90%.\" The gain you're claiming — 89.6 versus 89.1 last year — disappears inside that rounding, and the auditor reading the packet will notice the mismatch before the board does.","task":"Rewrite the sentence with figures precise enough to carry the claim they support.","tips":["Round to the precision your claim needs — a half-point gain needs decimals.","Never let rounding manufacture or erase a trend.","Consistent precision across a document is part of its credibility."],"focus":["precision","concision"],"placeholder":"Attendance is 89.6%, up half a point from 89.1% last year — the first year-over-year gain in three."},
    {"id":"precision-edu-senior-19","level":"senior","profession":"education","title":"Effect size in plain words","scenario":"The curriculum pilot produced a 0.2 standard-deviation gain — meaningful in education research, meaningless as a phrase to your board. Translate it without overselling it.","task":"Write 1-2 sentences that render the effect in plain, honest terms.","tips":["Convert to something concrete: roughly two extra months of learning.","Say what it isn't — not transformative, but real and cheap at this price.","Overselling a modest effect burns the credibility your next ask needs."],"focus":["precision","audience"],"placeholder":"The pilot classrooms gained the equivalent of about two extra months of learning in a year — a modest but real effect, at a cost of $40 per student."},
    {"id":"precision-edu-senior-20","level":"senior","profession":"education","title":"'Aging buildings' with data","scenario":"Your capital request describes \"aging infrastructure across the campus.\" Every district in the state says that sentence. Yours has a 61-year-old boiler with three failures this winter and $84,000 in emergency repairs — say so.","task":"Rewrite the claim with the ages, failure counts, and repair spend.","tips":["Specific decay is fundable; general aging is background noise.","Lead with the worst verifiable fact — the boiler, not the aesthetic.","Emergency-repair spend is the number that proves waiting costs more."],"focus":["precision","impact"],"placeholder":"Our boiler is 61 years old and failed three times this winter — $84,000 in emergency repairs against a $310,000 replacement."},
    {"id":"precision-edu-senior-21","level":"senior","profession":"education","title":"Claim only what the evidence carries","scenario":"Reading scores jumped nine points the same year you launched the new reading block — and hired two interventionists, and changed the schedule. Your draft credits the reading block alone. A careful board member will unbundle it for you, publicly.","task":"Rewrite the claim to state honestly what the evidence supports.","tips":["Correlation with three changes at once is not attribution to one.","Say what you can: the package worked; unbundling comes next year.","Claiming too much now taxes every claim you make later."],"focus":["precision","clarity"],"placeholder":"Reading scores rose nine points in the first year of the new block, the added interventionists, and the schedule change together — I can't yet separate their effects, but the package is working."},
    {"id":"precision-edu-senior-22","level":"senior","profession":"education","title":"Per-pupil spending, apples to apples","scenario":"You want to tell the council your school spends less per pupil than the neighboring district. Their figure includes transportation and capital; yours doesn't. If anyone catches the mismatch, the whole testimony wobbles.","task":"Write the comparison sentence with the basis stated so it survives scrutiny.","tips":["State what's in the number: operating spend, excluding transport and capital.","Compare identical baskets or say explicitly where they differ.","One footnoted honest number outlasts a flattering mismatched one."],"focus":["precision","structure"],"placeholder":"On operating spend alone — excluding transportation and capital for both districts — we spend $11,240 per pupil against their $12,800."},
    {"id":"precision-edu-senior-23","level":"senior","profession":"education","title":"The one number to remember","scenario":"State results dropped today: forty pages of tables. You get three minutes at tonight's board meeting. The board will remember exactly one number — you get to choose which one, or the newspaper will choose for you.","task":"Deliver the opening sentence: the single number, with its meaning attached. Speak it aloud.","tips":["Pick the number that best represents the true story — not just the best number.","Attach the meaning in the same breath: what it says about the school.","Say it slowly enough to be written down."],"focus":["impact","precision"]},
    {"id":"precision-edu-senior-24","level":"senior","profession":"education","title":"Evidence for the counselor ask","scenario":"Your counselor request rests on the ratio: 480 students per counselor against a recommended 250. The skeptical question is coming: recommended by whom, and does the ratio actually change outcomes? Arm the number.","task":"Write 2-3 sentences that give the ratio its source and its outcome link.","tips":["Name the source of the standard — a national association is checkable.","Connect ratio to outcome: what improves when caseloads drop.","One local data point — our own referral backlog — grounds the national number."],"focus":["precision","impact"],"placeholder":"Our ratio is 480 to 1 against the American School Counselor Association's recommended 250. At current caseloads, students wait 11 days for a first appointment —"},
    {"id":"precision-edu-senior-25","level":"senior","profession":"education","title":"'Several incidents' in the safety report","scenario":"Your annual safety report says there were \"several incidents\" this year. The board approves this report as a public record. 'Several' will read as evasive the moment anyone files a records request and counts.","task":"Rewrite the line with counts by category and the year-over-year direction.","tips":["Public records deserve exact counts — you'll be held to them anyway.","Categorize: fights, threats, weapons-policy violations — lumping alarms people.","Add the trend; a precise count without direction invites the worst assumption."],"focus":["precision","clarity"],"placeholder":"We recorded 14 physical altercations, 3 threat assessments, and 1 weapons-policy violation this year — down from 19, 5, and 2 last year."}
  ],
  "executive-presence": [
    {"id":"presence-edu-senior-01","level":"senior","profession":"education","title":"Own the redistricting recommendation","scenario":"Your boundary study ends with three options presented neutrally, pros and cons balanced. The board hired your judgment, not a menu — and tonight someone will ask, 'What do you recommend?' Decide before they make you.","task":"Rewrite the closing so it recommends one option and treats the others as considered and rejected.","tips":["A neutral menu reads as fear of being wrong — take the position.","Recommend one, then say briefly why each alternative loses.","'It depends on the board's priorities' is a dodge; state your read of the priorities."],"focus":["impact","structure"],"placeholder":"I recommend Option B. It moves the fewest students — 140 — keeps siblings together, and balances buildings for a decade. Option A is cheaper but reopens this fight in three years —"},
    {"id":"presence-edu-senior-02","level":"senior","profession":"education","title":"Signpost the board presentation","scenario":"You have twelve minutes for the improvement-plan update and a room that doesn't know if you'll take five or fifty. An opening that maps the terrain projects command; diving into slide one projects hope.","task":"Write the two opening sentences that signpost what's coming and where you'll land.","tips":["Give the shape first: three results, one problem, one request.","Tell them where you'll land so no one wonders if you have a point.","Signposting also protects your time — the room lets you finish a mapped journey."],"focus":["structure","impact"],"placeholder":"I'll cover three results, one problem I haven't solved, and one request for the board — twelve minutes, then questions. The headline:"},
    {"id":"presence-edu-senior-03","level":"senior","profession":"education","title":"Separate the data from your read","scenario":"Your discipline-data readout blends what the numbers show with what you believe is causing it, so the board can't tell fact from interpretation. When one opinion gets challenged, the facts fall with it. Split them.","task":"Rewrite one mixed passage so the fact and your judgment are explicitly labeled.","tips":["Make the move visible: 'The data shows X. My read is Y.'","Owning the interpretation as yours builds trust in both halves.","Facts survive a challenged opinion only if you kept them separate."],"focus":["clarity","precision"],"placeholder":"The data shows referrals doubled in the two weeks after lunch was shortened. My read — and this is judgment, not proof — is that the schedule, not the students, is the driver."},
    {"id":"presence-edu-senior-04","level":"senior","profession":"education","title":"The recommendation you're afraid to make","scenario":"Every indicator says the underenrolled German program should close: eleven students across four sections, and a retirement that makes this the year. Your draft calls it \"an area for continued study.\" The board deserves your actual view.","task":"Write the recommendation you actually believe, stated with directness and care.","tips":["Softening a real conclusion into 'further study' serves you, not students.","Be direct about the program and generous about its history — both at once.","If your evidence points somewhere, arriving there is the job."],"focus":["impact","clarity"],"placeholder":"I recommend we close the German program at year's end. Eleven students across four sections can't justify a full position —"},
    {"id":"presence-edu-senior-05","level":"senior","profession":"education","title":"Purge the hedges","scenario":"Your budget-meeting notes read: \"I think maybe we could possibly look at perhaps adjusting the athletics allocation.\" Four hedges on one thought. The board hears each one as a reason to wait.","task":"Rewrite the sentence with the hedges gone and the position owned.","tips":["One calibrated qualifier is honest; four is static.","Replace 'maybe we could look at' with 'I propose.'","If you're genuinely unsure, say what would resolve it — that's confidence too."],"focus":["concision","impact"],"placeholder":"I propose cutting the athletics allocation 8% and protecting classroom aides."},
    {"id":"presence-edu-senior-06","level":"senior","profession":"education","title":"Confident without overpromising","scenario":"Parents at tonight's forum want to hear the new safety plan makes the school safe, full stop. You can't honestly promise that — but hedged mush will frighten them more. Calibrate: confident about what you control, honest about what you can't.","task":"Write the 2-3 sentence statement that projects earned confidence without a promise you can't keep.","tips":["Be absolute about actions taken; be honest about guarantees no one can give.","'Here is exactly what changed' carries more comfort than 'everything is fine.'","Parents trust the leader who sounds in command of the details."],"focus":["audience","impact"],"placeholder":"I can't promise you a world without risk — no one can. Here's what I can promise: every exterior door now locks automatically, every visitor is screened, and we drill this plan monthly."},
    {"id":"presence-edu-senior-07","level":"senior","profession":"education","title":"The first all-staff address","scenario":"You're the new principal of a school that's had three principals in four years. The staff's unspoken question at your first address isn't about your plans — it's whether you'll actually lead or just pass through. Your opening ninety seconds answer it.","task":"Deliver the opening of your first address — decided, specific, unhurried. Speak it aloud.","tips":["Say one thing you've decided and one thing you refuse to decide until you've listened.","Specifics signal command; vision statements signal a résumé stop.","Slow down — pace is presence."],"focus":["impact","audience"]},
    {"id":"presence-edu-senior-08","level":"senior","profession":"education","title":"Opening the hostile forum","scenario":"Two hundred people are in the gym for the redistricting forum, and a third of them arrived angry. Your opening two minutes decide whether this is a meeting you're leading or one that's happening to you.","task":"Deliver the opening: name the tension, state the process, own your role. Speak it aloud.","tips":["Name the anger in the room before it names itself — calmly, without apology.","State what tonight decides and what it doesn't; a clear container lowers the temperature.","Never open a hard meeting by thanking people for their passion."],"focus":["audience","impact"]},
    {"id":"presence-edu-senior-09","level":"senior","profession":"education","title":"'Are you sure?' from the chair","scenario":"You've just recommended the seven-period schedule and the board chair leans in: 'Are you sure about this?' A flinch here undoes the whole presentation. You are sure — about the evidence, if not the future.","task":"Write your 2-sentence answer: confident, calibrated, and specific about what your confidence rests on.","tips":["'Yes' first — then say what the yes rests on.","Distinguish confidence in the analysis from certainty about outcomes.","Restating one piece of evidence beats restating your feelings."],"focus":["impact","precision"],"placeholder":"Yes. I'm sure the evidence points here — three schools our size made this move and kept the gains — and I'm sure the risks are ones we can manage, because we've planned for each one."},
    {"id":"presence-edu-senior-10","level":"senior","profession":"education","title":"The confident correction","scenario":"Last month you told the board the deficit was $410,000. A coding error surfaced; it's $540,000. How you deliver the correction determines whether the story is 'error found and controlled' or 'numbers can't be trusted.'","task":"Write the 2-3 sentence correction: the new number, the cause, the fix — no groveling.","tips":["State the corrected number first, plainly, before the explanation.","One sentence on cause, one on the control that now prevents it.","Overapologizing converts a correction into a confession."],"focus":["clarity","impact"],"placeholder":"The deficit is $540,000, not the $410,000 I reported in October. A grant was double-counted in the October close; the error is fixed, and month-end reconciliation now catches this class of mistake."},
    {"id":"presence-edu-senior-11","level":"senior","profession":"education","title":"Owning the unpopular calendar","scenario":"You've decided: professional development moves to Saturdays twice a year. Staff hate it, and your draft announcement blames the district calendar committee. Deferred blame reads as weakness — and staff can smell it.","task":"Rewrite the announcement so you own the decision and the reason, without hiding behind the committee.","tips":["'I decided' is stronger and more respected than 'it was determined.'","Give the real reason once, clearly — don't relitigate it in the memo.","Own it now or lose the authority you'll need for the next hard call."],"focus":["clarity","impact"],"placeholder":"I've decided to move two PD days to Saturdays next year. Here's why: it returns six instructional days to students —"},
    {"id":"presence-edu-senior-12","level":"senior","profession":"education","title":"Your position on the merger","scenario":"The superintendent asks you point-blank in a cabinet meeting: should the two middle schools merge? You've studied it. 'There are strong arguments on both sides' is true and useless — and everyone in the room knows it.","task":"Write your 2-3 sentence answer: your position, your top reason, your biggest caveat.","tips":["Position first — the room already knows the arguments on both sides.","One best reason, stated with a number if you have it.","A named caveat is calibration; an unnamed hedge is evasion."],"focus":["impact","clarity"],"placeholder":"Merge them. Enrollment supports one strong school, not two thin ones — combined, we restore full arts and a real counseling team. My caveat: the transition year needs —"},
    {"id":"presence-edu-senior-13","level":"senior","profession":"education","title":"Purge the passive voice","scenario":"Your incident memo to the board reads: \"Mistakes were made in the notification process, and protocols were not followed.\" By whom? The passive voice is doing what it always does — hiding the actor, and everyone notices.","task":"Rewrite the two sentences in active voice, with owners attached.","tips":["Every passive sentence in a hard memo reads as evasion.","Name the actor — including when the actor is you or your office.","Active voice plus a fix reads as command; passive plus regret reads as spin."],"focus":["clarity","precision"],"placeholder":"My office notified families four hours late — the on-call protocol failed, and I own that. Here's what changed:"},
    {"id":"presence-edu-senior-14","level":"senior","profession":"education","title":"The cover memo that sounds decided","scenario":"Your budget cover memo opens: \"This document attempts to outline some possible approaches to the funding situation.\" Attempts. Some. Possible. Situation. The board reads presence — or its absence — in the first line.","task":"Rewrite the opening sentence so it sounds like a leader transmitting a plan.","tips":["'This is my recommended budget' beats 'this attempts to outline.'","Kill 'situation' — name the thing: a $540,000 shortfall.","The memo's first sentence sets how seriously the whole packet is read."],"focus":["impact","concision"],"placeholder":"This is my recommended budget for closing the $540,000 shortfall: three cuts, one investment, no layoffs."},
    {"id":"presence-edu-senior-15","level":"senior","profession":"education","title":"Kill the options paper","scenario":"Your cell-phone-policy memo lays out four options and asks the board to choose. You've run the school for six years; you know which one works. Asking the board to pick your policy for you is abdication dressed as deference.","task":"Rewrite the ask: your recommendation, the runner-up and why it loses, and what you need from the board.","tips":["Boards approve recommendations; they shouldn't have to write them.","Show your work on one rejected option — that's judgment made visible.","Ask for the decision you need, not for direction."],"focus":["structure","impact"],"placeholder":"I recommend the pouch system — phones locked at first bell, returned at dismissal. The lighter-touch option fails on the evidence:"},
    {"id":"presence-edu-senior-16","level":"senior","profession":"education","title":"The vision in one sentence","scenario":"Your strategic plan has five pillars, twenty-three initiatives, and no sentence anyone can repeat. At tomorrow's launch, staff and families will remember exactly one line — if you give them one worth remembering.","task":"Write the single sentence that carries the plan — concrete, sayable, yours.","tips":["A vision sentence names a change, not a value: what will be different.","If a parent can't repeat it at pickup, it's not done.","Plain words carry conviction; 'leverage excellence' carries nothing."],"focus":["impact","concision"],"placeholder":"In three years, every child who enters this school reads at grade level by third grade — and we will publish our progress every semester."},
    {"id":"presence-edu-senior-17","level":"senior","profession":"education","title":"The soundbite you actually control","scenario":"The local station wants fifteen seconds on the budget vote. Whatever you say will be cut to one sentence — so speak in the sentence you want aired, instead of paragraphs they'll cut for you.","task":"Deliver the fifteen-second statement: one message, said like a decision. Speak it aloud.","tips":["Write the quote you want to see, then say only that.","One message; a second point gives the editor a choice you don't control.","Calm, declarative, no conditional clauses."],"focus":["concision","impact"]},
    {"id":"presence-edu-senior-18","level":"senior","profession":"education","title":"Contain the hard meeting","scenario":"Tonight's agenda has the boundary vote, and public comment could run all night. Presence here is structural: state the container — what will be heard, decided, and deferred — before emotion sets the agenda for you.","task":"Write the 3-sentence agenda framing you'll read at the top of the meeting.","tips":["Say what gets decided tonight and what explicitly does not.","State the comment format as fact, not as a request for cooperation.","A firm container is a kindness — drift punishes everyone equally."],"focus":["structure","audience"],"placeholder":"Tonight the board hears public comment on the boundary proposal — two minutes per speaker, one hour total — and then votes on Option B. Transportation details are not decided tonight;"},
    {"id":"presence-edu-senior-19","level":"senior","profession":"education","title":"Confidence with the risks attached","scenario":"You're launching the school's first team-teaching model. You believe in it, and it might not work. Staff will follow confidence, but they'll also remember whether you were honest at the start. Do both.","task":"Write the 3-sentence launch statement: conviction, the named risks, and the review point.","tips":["State the belief plainly — then name the two real risks yourself.","A named review date makes confidence accountable instead of blind.","Honesty about risk at launch buys patience when the risk shows up."],"focus":["impact","clarity"],"placeholder":"I believe team teaching is the best bet we have for sixth grade, and I'm putting my judgment behind it. Two honest risks: planning time and grading consistency. We review the data together on December 15 —"},
    {"id":"presence-edu-senior-20","level":"senior","profession":"education","title":"Retaking the room","scenario":"Public comment just ran ninety minutes past the limit, two speakers shouted, and one board member walked out. You're next on the agenda. The room needs someone to sound like the adult — tonight that's you.","task":"Deliver the first three sentences that retake the room: steady, unhurried, forward. Speak them aloud.","tips":["Lower your pace when the room's pace is high — contrast is command.","Acknowledge the heat in one sentence; do not re-argue anything said.","Then move: state what happens next, and start doing it."],"focus":["audience","impact"]},
    {"id":"presence-edu-senior-21","level":"senior","profession":"education","title":"End with a decision","scenario":"Your leadership-team meetings keep ending with \"let's keep thinking about this\" — and the master schedule has now been 'thought about' for six weeks. Today's meeting ends differently, and how you close it is the difference.","task":"Write the closing 2-3 sentences: the decision, who does what by when, and what would reopen it.","tips":["'We've decided' is the sentence your meetings have been missing.","Assign the next action with a name and a date in the same breath.","State what evidence would reopen the question — then close it."],"focus":["structure","impact"],"placeholder":"We're going with the rotating block — decided. Maria drafts the teacher assignments by Friday; I take it to the district Monday. This reopens only if the state changes the testing window."},
    {"id":"presence-edu-senior-22","level":"senior","profession":"education","title":"The union table opener","scenario":"Contract negotiations open tomorrow. The union expects either a stonewall or a pushover; your opening statement can set a third tone — firm on the constraint, genuine on the shared ground.","task":"Write the 3-sentence opening statement: the constraint stated as fact, the shared interest, the way you'll work.","tips":["State the fiscal constraint as arithmetic, not as posture.","Name the real shared interest — retention — before the first disagreement.","Firm and respectful is a register; practice holding both at once."],"focus":["audience","impact"],"placeholder":"The revenue picture is what it is: 2.1% new money, and I won't pretend otherwise. What we share is a retention problem that's costing both of us —"},
    {"id":"presence-edu-senior-23","level":"senior","profession":"education","title":"Label the judgment call","scenario":"The enrollment data is ambiguous: the decline could be a blip or the start of a slide. The board wants your read. Presence isn't pretending the data is clear — it's owning a judgment while labeling it as one.","task":"Write 2-3 sentences that state the data, label your judgment as judgment, and commit to a checkpoint.","tips":["'The data is consistent with both; my judgment is —' is a leadership sentence.","Committing to a checkpoint makes a judgment call accountable.","Refusing to read ambiguous data isn't rigor; it's hiding."],"focus":["precision","impact"],"placeholder":"Two years of decline is consistent with a blip or a trend — the data alone won't tell us which. My judgment is that the charter expansion makes this a trend, and I'm planning accordingly; February's registration numbers will test me."},
    {"id":"presence-edu-senior-24","level":"senior","profession":"education","title":"Rank your priorities out loud","scenario":"A board member interrupts your budget presentation: 'If you could only keep one — the counselor, the reading coach, or the technology refresh — which one?' The honest ranking exists in your head. Saying it out loud is the presence test.","task":"Write your 2-sentence answer: the ranking, owned, with the reason for the top pick.","tips":["Answer the question asked — a ranking, not a plea for all three.","One reason for the top choice, tied to your school's actual data.","Refusing to rank tells the board you haven't decided what matters."],"focus":["clarity","impact"],"placeholder":"The reading coach, without hesitation — third-grade reading is the lever everything else in this building depends on. Then the counselor, then technology."},
    {"id":"presence-edu-senior-25","level":"senior","profession":"education","title":"Stop hiding behind the district","scenario":"For months you've introduced hard news with 'the district has decided' — even for calls that were substantially yours. Staff have noticed. Today's grading-policy announcement is yours, and it's time your language said so.","task":"Rewrite the announcement's opening so you own the decision you actually made.","tips":["'I've decided' costs more and buys more than 'the district requires.'","Borrowed authority is a loan — staff eventually check the terms.","Own the decision and the reason; delegate neither."],"focus":["clarity","impact"],"placeholder":"I've decided we're adopting the 50-point floor for first-quarter grades. The district allows it; the decision to do it here is mine, and here's my reason:"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-edu-senior-01","level":"senior","profession":"education","title":"'Yes or no — will scores go up?'","scenario":"A board member cuts off your assessment presentation: 'Yes or no — will scores go up this year?' Your instinct is to explain the intervention model. She asked a yes/no. Answer that first.","task":"Write the 2-3 sentence answer that leads with yes or no, then the one condition.","tips":["Answer the literal question in the first three words.","Then the single condition your yes depends on — not the whole model.","Leading with methodology instead of an answer reads as dodging."],"focus":["clarity","impact"],"placeholder":"Yes — modestly, if attendance holds. The intervention math only works for students who are in the building —"},
    {"id":"pressure-edu-senior-02","level":"senior","profession":"education","title":"'Why should I keep my kid here?'","scenario":"At the community forum, a father stands up: 'The charter is two miles away and their scores are higher. Why should I keep my kid here?' Two hundred parents are waiting for your answer, and a brochure recitation will lose all of them.","task":"Write your 3-4 sentence answer: direct, specific, no defensiveness about the question.","tips":["Honor the question — it's the most legitimate one a parent can ask.","Answer with two specifics the charter can't match, not with loyalty appeals.","Concede what's true in the comparison; it buys belief for the rest."],"focus":["audience","impact"],"placeholder":"That's the right question, and I'll answer it straight. Their composite score is higher; ours is rising faster — and here are two things your son gets here that he won't get there:"},
    {"id":"pressure-edu-senior-03","level":"senior","profession":"education","title":"The honest 'I don't know' with a path","scenario":"At the board meeting, a member asks whether the new state funding formula nets your district more or less money. The analysis genuinely isn't done. Bluffing a direction risks being wrong in the minutes forever.","task":"Write the 2-3 sentence response: honest admission plus exactly how and when you'll answer.","tips":["'I don't know yet' is credible; a guessed number in the minutes is a liability.","Attach the path immediately: who's running the model and the date it lands.","Boards forgive unfinished analysis; they don't forgive confident wrong answers."],"focus":["clarity","precision"],"placeholder":"I don't know yet, and I won't guess a number into the record. Our business office runs the formula model this week; you'll have the answer in writing by Friday."},
    {"id":"pressure-edu-senior-04","level":"senior","profession":"education","title":"'These gains are just teaching to the test'","scenario":"You present the nine-point reading gain and a skeptical board member waves it off: 'That's just teaching to the test.' Arguing abstractly about pedagogy feeds the fight. You have specific evidence the gains are real — use it.","task":"Write the 2-3 sentence response that meets the skepticism with specific grounding.","tips":["Don't defend testing in general — ground this specific gain.","Cite converging evidence: a second measure, classroom-level results, the trend.","Specifics defeat skepticism; indignation feeds it."],"focus":["precision","impact"],"placeholder":"Fair challenge — so I checked it against measures we don't coach for. Our independent reading inventory shows the same nine-point pattern, and library circulation is up 30% —"},
    {"id":"pressure-edu-senior-05","level":"senior","profession":"education","title":"The reporter and the arrest","scenario":"A teacher was arrested last night on charges unrelated to school. A reporter calls: 'What can you tell me?' Legal counsel has cleared exactly three facts. Pressure will pull you past them; the transcript will keep whatever you say.","task":"Write your on-record statement: the cleared facts, the boundary stated plainly, the process next.","tips":["Say what you can fully and stop — a hard stop reads better than a trailing hedge.","State why you can't say more: personnel law, not preference.","Name the process in motion; 'we are investigating' with a next step isn't a dodge."],"focus":["precision","audience"],"placeholder":"I can confirm the teacher was placed on administrative leave this morning pending the district's review. Personnel law limits what I can say beyond that —"},
    {"id":"pressure-edu-senior-06","level":"senior","profession":"education","title":"'Isn't this just the district abandoning us?'","scenario":"At the consolidation meeting, a grandmother asks the question the whole gym is thinking: 'Isn't this just the district giving up on our side of town?' It's a feeling wearing a question's clothes — and it deserves a real answer, not a org-chart explanation.","task":"Write your 3-sentence answer: meet the feeling, answer the substance, name the commitment.","tips":["Acknowledge the loss as real before you answer the charge.","Then answer the actual claim with the actual facts — investment follows the students.","End with a commitment concrete enough to be checked later."],"focus":["audience","impact"],"placeholder":"I hear what's underneath that question, and the loss is real — this building has held three generations. But watch where the money goes:"},
    {"id":"pressure-edu-senior-07","level":"senior","profession":"education","title":"Your data challenged in front of staff","scenario":"At the faculty meeting, the union rep stands: 'Your overtime numbers are wrong — you're undercounting duty coverage.' Sixty teachers are watching how you handle being challenged. He might be partly right.","task":"Write your 2-3 sentence response: composed, specific, open to the correction without surrendering the point.","tips":["Never defend a number you haven't rechecked — offer the check.","'If duty coverage is missing, I want it in the count' costs nothing and wins the room.","The audience is judging your temperature, not just your data."],"focus":["clarity","audience"],"placeholder":"You might be right about duty coverage — if it's missing from the count, I want it in there. Let's sit down with the raw timesheets Thursday;"},
    {"id":"pressure-edu-senior-08","level":"senior","profession":"education","title":"'Why is the ranking down?'","scenario":"The state report cards dropped and your school slipped from a B to a C. A board member asks why, in public session, with a journalist in the second row. You know the answer is partly methodology and partly real — say both without hiding behind either.","task":"Write the 2-3 sentence answer that owns the real part and explains the methodology part, in that order.","tips":["Own the real decline first — leading with methodology reads as excuse.","Then the formula change, in one sentence, with the size of its effect.","End on the action already underway, with a date."],"focus":["clarity","precision"],"placeholder":"Two things are true. Our math growth genuinely slowed — that's on us and here's the plan — and the state also reweighted the formula, which accounts for about half the drop."},
    {"id":"pressure-edu-senior-09","level":"senior","profession":"education","title":"The charter comparison gotcha","scenario":"At the budget hearing: 'The charter gets better results with less money per student. Why do you need more?' The comparison omits special education, transportation, and who they counsel out — but a defensive data lecture will lose the room.","task":"Write the 2-3 sentence answer: concede the surface, correct the comparison, land your point.","tips":["Start by taking the question seriously — the numbers as quoted are real.","Correct the basket in one plain sentence: we serve every child who arrives.","Make the correction concrete: name what's in our number and not theirs."],"focus":["precision","audience"],"placeholder":"Those numbers are real, and the comparison is missing something: our figure includes special education, buses, and every student who walks in the door in February. Theirs doesn't —"},
    {"id":"pressure-edu-senior-10","level":"senior","profession":"education","title":"'Why wasn't I called first?'","scenario":"A mother is in your office, furious that she learned about her son's playground injury from another parent's text before the school called. The nurse followed protocol; the protocol was too slow. Both things are true.","task":"Write your 2-3 sentence response: direct answer, no protocol-hiding, the fix.","tips":["Answer her actual question first: here's what happened to the call.","Don't shelter behind 'protocol was followed' when the protocol failed her.","The fix, concretely: what changes about the next parent's phone call."],"focus":["audience","clarity"],"placeholder":"You should have heard from us first, and you didn't — the call went out 40 minutes after the incident because our protocol waits for the nurse's full assessment. That's too slow, and I'm changing it:"},
    {"id":"pressure-edu-senior-11","level":"senior","profession":"education","title":"'How many teachers are leaving because of you?'","scenario":"In public comment, a departing teacher's spouse asks: 'Twelve teachers have quit in two years. How many left because of your leadership?' It's designed to wound. Some of it may even be fair. Two hundred people are watching your face.","task":"Write your 2-3 sentence answer: composed, honest about what exit data shows and doesn't, no counterattack.","tips":["Take a breath in the text itself — a measured opening sentence, not a parry.","Give the honest data: what exit interviews attribute, and their limits.","'Some of that may be about me' — owned calmly — disarms more than any defense."],"focus":["audience","impact"],"placeholder":"I won't pretend that number doesn't concern me — it does. Exit interviews name pay and commute most often, but I'd be foolish to claim none of it is about leadership, and I've asked the district to survey leavers independently."},
    {"id":"pressure-edu-senior-12","level":"senior","profession":"education","title":"Untangle the compound question","scenario":"A board member unloads three questions in one: 'Why is the busing contract over budget, who approved the change order, and does this affect the classroom technology money?' Answering them tangled guarantees a muddle and a follow-up you'll like less.","task":"Write the answer that names the three parts and takes them one at a time, in the order that serves clarity.","tips":["Say the structure out loud: 'Three questions in there — let me take them in order.'","Answer each in one or two sentences before touching the next.","Reordering is allowed: answer the money question first if it defuses the rest."],"focus":["structure","clarity"],"placeholder":"There are three questions in there, and they deserve separate answers. The overage: $63,000, driven by fuel escalators. The change order: approved by my office, within delegated authority. The technology money: untouched —"},
    {"id":"pressure-edu-senior-13","level":"senior","profession":"education","title":"'Did you know before it hit Facebook?'","scenario":"A parent group's post about mold in the portable classrooms went viral overnight. At tonight's meeting: 'Did you know about this before it hit Facebook?' You did — a work order was filed two weeks ago. The truthful answer sounds bad, and the untruthful one is fatal.","task":"Write the honest answer: what you knew, when, what was already underway, and what the gap was.","tips":["Answer the yes first — a discovered lie ends careers; a hard truth ends a news cycle.","Immediately attach the timeline of action already in motion.","Name the real gap — communication, not remediation — and the fix for it."],"focus":["clarity","impact"],"placeholder":"Yes — we found it two weeks ago during a routine inspection, filed remediation orders the same day, and had air-quality testing scheduled. What we didn't do was tell you, and that was a mistake I'm correcting tonight."},
    {"id":"pressure-edu-senior-14","level":"senior","profession":"education","title":"Reject the loaded premise","scenario":"A speaker at public comment begins: 'Since discipline is completely out of control at this school, what are you going to do about it?' Accepting the premise concedes the headline; attacking the speaker loses the room. The referral data tells a calmer story.","task":"Write the 2-3 sentence answer that resets the premise with data, then answers the fair question inside it.","tips":["Reset the frame without scorn: 'Let me start with what the data shows.'","Then honor the legitimate kernel — there IS a real concern worth answering.","Correct the premise once; don't argue it repeatedly."],"focus":["precision","audience"],"placeholder":"Let me start with what the data shows: referrals are down 12% from last year, so 'out of control' isn't the picture. But there's a real concern inside your question — the cafeteria incidents — and here's what we're doing:"},
    {"id":"pressure-edu-senior-15","level":"senior","profession":"education","title":"'Cut administration instead'","scenario":"At the budget hearing, the applause line arrives: 'Why cut art teachers when the district office is full of administrators?' The room claps. Your central-office costs are actually below the state average — but a statistic against a standing ovation needs careful footing.","task":"Write the 2-3 sentence answer: respect the instinct, give the number, show your own skin in the game.","tips":["Agree with the principle first — overhead should face pressure before classrooms.","One clean comparison number, sourced, not three.","Name what administration already gave up; shared sacrifice earns the math a hearing."],"focus":["audience","precision"],"placeholder":"I agree with the principle — cuts should hit the office before the classroom, and they have: we've frozen two central positions and cut my own office budget 9%. Even so, our admin costs run 4.1% of budget against a state average of 5.3% —"},
    {"id":"pressure-edu-senior-16","level":"senior","profession":"education","title":"The date you can't promise","scenario":"A parent asks, simply: 'When will the roof be fixed?' The honest answer involves a bid process you don't control. A guessed date will be remembered; 'I don't know' alone will be resented. There's a third way: the date you control, plus the process you don't.","task":"Write the 2-sentence answer that gives what's certain, bounds what isn't, and names when they'll know more.","tips":["Give the certain part: bids close March 1 — that date is real.","Bound the uncertain part honestly: construction is 6-10 weeks after award.","Promise the update, not the outcome: 'you'll have the schedule by March 15.'"],"focus":["precision","clarity"],"placeholder":"Bids close March 1, and construction takes six to ten weeks from award — so realistically, mid-May at best. What I can promise: you'll have the contractor's actual schedule by March 15."},
    {"id":"pressure-edu-senior-17","level":"senior","profession":"education","title":"'Can you absorb another 5%?'","scenario":"The superintendent asks in the cabinet meeting: 'If the levy fails, can your building absorb another five percent?' The loyal answer is yes; the true answer is 'only by cutting things you've told the community are protected.' Say the true one.","task":"Write the 2-3 sentence answer: direct, specific about what 5% actually means, loyal to the facts.","tips":["Answer honestly: 'not without touching X' is an answer, not insubordination.","Translate the percentage into its real contents — positions, programs.","Offer the analysis, not just the resistance: here's the least-harm version."],"focus":["clarity","precision"],"placeholder":"Not without breaking commitments we've made publicly — five percent is $310,000, which is the reading interventionists plus activity buses. If it comes to that, here's the least-harm sequence I'd propose:"},
    {"id":"pressure-edu-senior-18","level":"senior","profession":"education","title":"The question outside your lane","scenario":"At the forum, a parent demands to know why the district changed the math curriculum. You privately disagree with the change, you didn't make the decision, and undermining the district on stage will follow you back to the office. Answer without ducking or disloyalty.","task":"Write the 2-3 sentence answer: what's yours to answer, what isn't, and where the real answer lives.","tips":["Own your part: how this school implements it and supports kids through the switch.","Route the decision question honestly without an eye-roll: name who decided and how to reach them.","Daylight between you and the district, aired publicly, costs more than it vents."],"focus":["audience","structure"],"placeholder":"The curriculum decision was made at the district level, and I'll get you the right contact and the adoption rationale tonight. What's mine to answer is how we make it work in this building —"},
    {"id":"pressure-edu-senior-19","level":"senior","profession":"education","title":"The personnel question you can't answer","scenario":"After a popular coach's quiet departure, a board member asks in open session: 'Why did he really leave?' You know exactly why, and the law forbids you to say. 'No comment' feeds the rumor; the full truth breaks the law. Walk the line.","task":"Write the answer that states the boundary as principle, gives what is public, and declines the rest without smirking.","tips":["State the rule as protecting everyone — including every teacher watching.","Give the one public fact plainly: resignation accepted, effective when.","Don't hint. A knowing hedge is a leak with deniability."],"focus":["precision","audience"],"placeholder":"Personnel law doesn't let me discuss the circumstances of anyone's departure — a protection every employee here counts on. What's public: he resigned effective March 1, and we thank him —"},
    {"id":"pressure-edu-senior-20","level":"senior","profession":"education","title":"'Is the school safe?' — live","scenario":"After a threat and a two-hour lockdown, a TV reporter asks the only question that matters: 'Is the school safe?' The answer will lead the six o'clock news. Fear-driven hedging alarms; hollow assurance insults. Speak it.","task":"Deliver your on-camera answer: direct, calibrated, grounded in the specific facts of today. Speak it aloud.","tips":["Lead with the direct answer, calibrated: 'Yes — and here is what today showed.'","Ground it in today's specifics: the protocol worked, police cleared the building.","One sentence of what happens next; then stop talking."],"focus":["impact","audience"]},
    {"id":"pressure-edu-senior-21","level":"senior","profession":"education","title":"Correct the board member gently","scenario":"In open session, a friendly board member argues for your budget using the wrong number — she says the deficit is $54,000 when it's $540,000. Letting it stand plants a landmine; correcting her clumsily embarrasses your best ally on camera.","task":"Write the 1-2 sentence correction that fixes the record and protects the ally.","tips":["Correct the number, not the person: 'one clarification for the record.'","Take the blame for the confusion if there's any to take — cheap and gracious.","Do it now; a wrong number in the minutes compounds monthly."],"focus":["precision","audience"],"placeholder":"One clarification for the record, and the confusion is probably my slide's fault: the figure is $540,000, not $54,000 — which strengthens the point Ms. Alvarez is making."},
    {"id":"pressure-edu-senior-22","level":"senior","profession":"education","title":"'What's your biggest failure this year?'","scenario":"At your public evaluation, a board member asks: 'What's your biggest failure this year?' A dodge reads as unselfaware; a trivial 'I work too hard' answer reads as contempt. You have a real one: the sixth-grade math slide you saw late.","task":"Write the 2-3 sentence answer: the real failure, named plainly, with what it taught and changed.","tips":["Pick a real failure with real consequences — the room can tell.","Own the mechanism: what you missed and why you missed it.","End on the changed system, not on a promise to care more."],"focus":["clarity","impact"],"placeholder":"Sixth-grade math. The benchmark data showed the slide in October and I didn't move resources until February — I treated one bad data point as noise. I now review grade-level data monthly with the team, in person —"},
    {"id":"pressure-edu-senior-23","level":"senior","profession":"education","title":"The follow-up you hoped wouldn't come","scenario":"You reported the turf-field project on budget. The follow-up lands: 'Including the drainage change order?' It isn't — with the change order, you're $47,000 over. The board member clearly already knows. This answer decides whether the story is the overrun or your candor.","task":"Write the answer: the corrected full number first, no wriggle, then the cause and the offset.","tips":["Concede immediately and completely — partial concessions invite excavation.","Give the full picture in one breath: base, change order, total, overage.","Then the plan for the $47,000; the room forgives overruns with owners."],"focus":["clarity","precision"],"placeholder":"You're right, and I should have led with it: including the drainage change order we're $47,000 over — $1.29 million against $1.24. The overage is covered by —"},
    {"id":"pressure-edu-senior-24","level":"senior","profession":"education","title":"Neutralize, then answer","scenario":"A speaker asks: 'How much more of our money are you going to waste on consultants who tell you what anyone could see?' Somewhere inside is an answerable question about the $60,000 facilities study. Restate it fairly out loud, then answer the fair version.","task":"Write the restatement plus answer — 3 sentences: the neutral rephrase, the number and what it bought, the judgment call owned.","tips":["Restate without sarcasm: 'The question is whether the study was worth $60,000.'","Answer with what the spend produced and what it prevented.","Own the judgment: 'I'd make the same call again' or 'I'd scope it differently' — pick one."],"focus":["structure","audience"],"placeholder":"The fair question in there is whether the $60,000 facilities study was worth it. It found the roof failure eight months before it would have found us — that timing difference alone saved roughly $200,000 in emergency work —"},
    {"id":"pressure-edu-senior-25","level":"senior","profession":"education","title":"The gauntlet: five questions, five minutes","scenario":"Budget Q&A, closing stretch: five board members, five queued questions — the deficit driver, the counselor ask, the charter comparison, the reserve policy, and 'what happens if the levy fails.' You have five minutes for all of them. Triage out loud and answer.","task":"Deliver the five answers, one or two sentences each, signposted so the room can follow. Speak it aloud.","tips":["Announce the plan: 'Five questions — I'll take them in thirty seconds each.'","One headline sentence per answer; offer written follow-up for depth.","Finishing on time with all five answered IS the presence move."],"focus":["structure","concision"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-edu-senior-01","level":"senior","profession":"education","title":"Before and after the counselor investment","scenario":"Your counselor proposal lists caseload ratios and service minutes. The board approves pictures, not ratios: what a struggling ninth-grader's Tuesday looks like now, and what it looks like funded. Paint the change.","task":"Write the 3-4 sentence before/after that makes the investment vivid.","tips":["Contrast the painful present with the specific funded future — the gap is the sale.","Make the after-state concrete: seen within two days, not 'improved access.'","The ratio is evidence; the Tuesday is the argument."],"focus":["impact","audience"],"placeholder":"Today, a ninth-grader in crisis waits eleven days to see a counselor — most stop asking by day three. Funded, that student is seen within 48 hours —"},
    {"id":"narrative-edu-senior-02","level":"senior","profession":"education","title":"A Tuesday in the renovated building","scenario":"Your bond presentation is floor plans and cost tables. Voters don't fall in love with load-bearing walls. Somewhere in those drawings is a Tuesday morning in 2028 — a kid walking into a building that works. Show them that.","task":"Write the 3-4 sentence walkthrough of an ordinary school day after the bond passes.","tips":["Pick one student and walk her through the morning — concrete beats panoramic.","Every detail should trace back to a real line item, or it's fantasy.","End where the money meets learning: the classroom, not the lobby."],"focus":["impact","audience"],"placeholder":"It's a Tuesday in 2028. Maya walks through doors that lock behind her, into a hallway that's 68 degrees in January instead of 54 —"},
    {"id":"narrative-edu-senior-03","level":"senior","profession":"education","title":"Make absenteeism a person","scenario":"Your absenteeism slide says 18% — 112 students. The board has seen a hundred percentage slides. One anonymized, composite student — what her semester actually looks like at 30 absences — will do what the number can't. Pair them.","task":"Write the 3-sentence pairing: the one-student story, then the number that says she's not alone.","tips":["The story earns attention; the number proves scale — you need both, in that order.","Composite and anonymized, and say so: credibility survives, privacy holds.","Land on the mechanism: what 30 absences does to algebra, specifically."],"focus":["impact","precision"],"placeholder":"One of our ninth-graders missed 30 days last year — she failed algebra not because she can't do math, but because algebra builds and she kept returning to a subject that had moved on. There are 112 students in her position —"},
    {"id":"narrative-edu-senior-04","level":"senior","profession":"education","title":"Pre-empt the tax objection","scenario":"Your bond pitch is strong, and the strongest objection in the room is fixed-income seniors facing a tax increase. If you don't raise it, the first public comment will — and win. Raise it yourself, inside the pitch.","task":"Write the 2-3 sentences that name and answer the tax objection before anyone else can.","tips":["Name it in its strongest form — a retiree's real budget, not a strawman.","Answer with what exists: the senior exemption, the actual monthly figure.","Pre-empting the room's best objection converts its energy into your credibility."],"focus":["structure","audience"],"placeholder":"Let me raise the hardest objection myself: if you're retired on a fixed income, this is real money. Two facts for that room:"},
    {"id":"narrative-edu-senior-05","level":"senior","profession":"education","title":"The arc of the annual address","scenario":"Your state-of-the-school draft is a department-by-department inventory — athletics report, then facilities, then curriculum. Inventories inform; arcs move. This year has an actual story: the reading bet paid off, and now it funds the next bet.","task":"Write the 3-sentence spine of the address: where we were, what we bet, what we do next.","tips":["Find the through-line and hang every department on it — or cut the department.","The strongest arc: a risk taken, evidence returned, the next risk earned.","If the year's story were one sentence, the address is that sentence, expanded."],"focus":["structure","impact"],"placeholder":"Two years ago we bet big on early reading when the money said play it safe. This year the bet paid: nine points. Tonight I'll show you the evidence — and where we place the next one."},
    {"id":"narrative-edu-senior-06","level":"senior","profession":"education","title":"The story-data one-two","scenario":"You open the board pitch for the mentorship program with a moving story about one mentored student. A skeptical member's eyebrow says what she's thinking: anecdotes aren't evidence. She's right — unless the data lands in the next breath.","task":"Write the pivot: the sentence that closes the story and the sentence that scales it with data.","tips":["The story is a specimen, not a proof — say so before the skeptic does.","'Marcus isn't the exception; he's the median' is the hinge sentence.","One scaling statistic, then stop; three dilutes the punch."],"focus":["impact","precision"],"placeholder":"That's one student — and if Marcus were the exception, this would just be a nice story. He's the median: mentored students' GPAs rose 0.6 against 0.1 for the matched comparison group."},
    {"id":"narrative-edu-senior-07","level":"senior","profession":"education","title":"From mandate to meaning","scenario":"The new literacy curriculum is mandatory, and your draft staff announcement leans on that: required, adopted, effective August. Compliance gets you implementation; belief gets you results. Same facts — find the story worth believing.","task":"Rewrite the announcement's opening so it persuades before it requires.","tips":["Lead with the problem teachers already feel — the kids the old approach missed.","Position the mandate as the tool, not the reason.","One honest line about the transition cost buys more buy-in than enthusiasm."],"focus":["audience","impact"],"placeholder":"Every one of us has watched a fourth-grader fake-read — fluent aloud, lost inside. A fifth of our kids are doing it right now, and the old curriculum has no answer for them. The new one does —"},
    {"id":"narrative-edu-senior-08","level":"senior","profession":"education","title":"The donor pitch for the STEM lab","scenario":"You're meeting a local manufacturer's CEO about funding the $150,000 STEM lab. Your draft leads with the school's needs. Donors don't fund needs; they fund futures they can see themselves in — including a workforce pipeline his own plant is starving for.","task":"Write the 3-4 sentence pitch that casts the donor inside the story.","tips":["Open in his world: the machinist jobs he can't fill.","The lab is the bridge between his problem and your students.","Make the naming concrete: his company's name on the room his future hires learn in."],"focus":["audience","impact"],"placeholder":"You've told the Chamber you can't fill machinist positions — twelve open right now. Two miles away, I have 400 students who've never held a caliper. The lab I'm proposing is the bridge:"},
    {"id":"narrative-edu-senior-09","level":"senior","profession":"education","title":"The schedule change as a story","scenario":"Next year's later start time is announced in your draft as a logistics bulletin: new times, new bus routes, effective dates. Buried under the logistics is the actual story — a decision made for documented adolescent health reasons. Families deserve the why before the when.","task":"Rewrite the opening 2-3 sentences to lead with the story of the decision, then the logistics.","tips":["Lead with the reason: the evidence on teen sleep moved us to act.","One sentence of evidence makes the inconvenience feel purposeful.","Then the logistics, cleanly — the story earns their patience for the details."],"focus":["audience","structure"],"placeholder":"Next year, high school starts 55 minutes later — a decision we made because the evidence on adolescent sleep became too strong to ignore:"},
    {"id":"narrative-edu-senior-10","level":"senior","profession":"education","title":"The slide that becomes a story","scenario":"Your forum slide shows kindergarten readiness falling four straight years across the district's east side. You could read the trend line aloud — or you could tell the room what it means: a widening gap that arrives at kindergarten already two years deep.","task":"Write the 3-sentence spoken narration that turns the trend line into a story with stakes.","tips":["Name what the line IS in human terms: children arriving already behind.","Give the trajectory a destination: where this line points by 2030.","End with the fork: the story has two endings and tonight picks one."],"focus":["impact","clarity"],"placeholder":"This line is four years of five-year-olds arriving at kindergarten already behind — and each cohort a little further behind than the last. Left alone, it points somewhere specific:"},
    {"id":"narrative-edu-senior-11","level":"senior","profession":"education","title":"'We tried this before'","scenario":"Your teaming proposal for sixth grade is landing well until a veteran teacher says: 'We tried teaming in 2016. It collapsed in a year.' She's right, it did, and half the room remembers. Your persuasion now runs through that failure, not around it.","task":"Write the 2-3 sentence response that owns the failure and distinguishes this attempt.","tips":["Concede fully and specifically — vague concessions read as dodges.","Name the mechanism of the old failure, then the specific design change that addresses it.","'Here's what's different' only works after 'here's what went wrong.'"],"focus":["structure","impact"],"placeholder":"You're right — 2016 collapsed, and it collapsed for a reason we can name: teams got one shared period a month and no authority over their schedule. This design starts where that one broke:"},
    {"id":"narrative-edu-senior-12","level":"senior","profession":"education","title":"Recruiting the teacher everyone wants","scenario":"The physics teacher you want has three offers, two of them from districts that outpay you by $6,000. Your recruiting pitch can't win on the number, so it has to win on the story — what she gets to build here that the richer districts can't offer.","task":"Write the 3-4 sentence pitch that makes your school the compelling story despite the salary gap.","tips":["Name the gap yourself — pretending it away kills trust in the rest.","Sell what's scarce for her: autonomy, a program that's hers, kids who need her most.","Be specific about the offer behind the offer: what she'd build in year one."],"focus":["audience","impact"],"placeholder":"I'll be straight: two of your offers beat mine by $6,000, and I can't close that this year. Here's what I have that they don't: a physics program that's yours to build from the syllabus up —"},
    {"id":"narrative-edu-senior-13","level":"senior","profession":"education","title":"Cuts as choices, not losses","scenario":"Your budget-cut presentation reads as a funeral: a list of everything being lost. The board and community disengage from pure grief. The honest reframe isn't spin — it's that cuts are choices about what to protect, and your list protects the classroom.","task":"Rewrite the framing: 2-3 sentences that present the cuts as a defended set of priorities.","tips":["Lead with what survives and why: every classroom teacher, every reading program.","Present the cuts as the price of that protection — a chosen trade, not a raid.","Grief without agency demoralizes; a defended priority list can be argued with, and that's better."],"focus":["structure","impact"],"placeholder":"This budget protects two things absolutely: classroom staffing and early reading. Everything on the cut list is there because it isn't those two things —"},
    {"id":"narrative-edu-senior-14","level":"senior","profession":"education","title":"Why this school","scenario":"Enrollment is open and families are choosing. Your draft marketing letter lists amenities — the ones every school lists. The families you're losing want an answer to one question: what does this school believe about my child that the others don't?","task":"Write the 3-sentence core of the letter: the belief, the proof, the invitation.","tips":["Lead with a conviction, stated plainly enough to disagree with.","Prove it with one thing you actually do that the belief requires.","Amenity lists are interchangeable; convictions are not."],"focus":["audience","impact"],"placeholder":"We believe no child should be invisible in a hallway — which is why every adult in this building, including me, carries a list of ten students they check on by name, every week."},
    {"id":"narrative-edu-senior-15","level":"senior","profession":"education","title":"The full case in three moves","scenario":"You get eight minutes to persuade the board to fund all-day kindergarten. Your materials have twenty arguments; persuasion needs three, plus the strongest objection handled inside the pitch. Choose and sequence.","task":"Write the skeleton: three arguments in order, one sentence each, and the pre-empted objection with its answer.","tips":["Order for a decision: the child's stake, the evidence, the money — then the objection.","Cut seventeen arguments without mercy; the board remembers three at most.","Handle the cost objection yourself, with the offset attached."],"focus":["structure","impact"],"placeholder":"Three reasons, then the hard question. One: half-day kids lose the readiness gap race by October —"},
    {"id":"narrative-edu-senior-16","level":"senior","profession":"education","title":"Make 74 students visible","scenario":"Enrollment fell by 74 students, which drives the deficit you're defending tonight. To the council it's an abstraction — a line in a formula. Those 74 students are specific children who left for specific reasons, and their reasons are your argument for the investment plan.","task":"Write the 2-3 sentences that turn the 74 into a persuasive, human argument for the plan.","tips":["Break the number into its reasons: who left, and for what.","The reasons should point directly at your proposed fixes — that's the persuasion.","One family's sentence — 'we left for the arts program' — carries the whole set."],"focus":["impact","precision"],"placeholder":"We called every family who left. Thirty-one went to the charter's arts program, eighteen followed jobs out of the county, and the rest named one thing: class sizes. Two of those three reasons are fixable, and this plan fixes them —"},
    {"id":"narrative-edu-senior-17","level":"senior","profession":"education","title":"The alumni letter that earns the ask","scenario":"Your scholarship-fund letter to alumni opens with the ask and follows with the school's needs. Alumni don't give to needs; they give to the school that made them — and to the kid sitting in their old seat. Restructure: story, bridge, ask.","task":"Write the 3-sentence sequence: the story that reopens their connection, the bridge, the specific ask.","tips":["Open in their memory: the classroom, the teacher, the moment this school worked.","Bridge to the present: that seat is occupied by a kid with the same shot and less margin.","Then the ask, specific: $250 covers one student's exam fees for a year."],"focus":["audience","structure"],"placeholder":"Somewhere in this building is the room where it clicked for you — a teacher who saw something before you did. That seat is occupied today by a student with the same spark and a family that can't cover a $94 exam fee."},
    {"id":"narrative-edu-senior-18","level":"senior","profession":"education","title":"The mutual-gain frame at the union table","scenario":"You want the union to pilot a peer-observation model, and their opening read is 'evaluation by another name.' Pitched as your initiative, it dies. Pitched as the solution to a problem they've named for years — isolation, no growth pathway — it has a chance.","task":"Write the 3-sentence pitch built on the union's own stated interests.","tips":["Open from their platform: quote the interest they've put in writing.","Design features that prove it isn't evaluation: no ratings, teacher-controlled, firewalled from files.","Offer the kill switch: a joint review with real power to end the pilot."],"focus":["audience","structure"],"placeholder":"Your own bargaining survey said it: teachers feel isolated and see no growth path that doesn't leave the classroom. This pilot is aimed at exactly that — no ratings, no file, observers chosen by teachers —"},
    {"id":"narrative-edu-senior-19","level":"senior","profession":"education","title":"The long game, made visible","scenario":"You're asking the board to fund kindergarten literacy aides whose payoff — third-grade reading scores — arrives after two board elections. The cost is now; the win is invisible for three years. Persuasion has to make the future evidence visible tonight.","task":"Write the 2-3 sentences that make a three-year payoff fundable today.","tips":["Name the timing problem yourself — boards respect the honesty and it defuses the objection.","Give them interim mile-markers they'll see before the payoff: mid-year decoding data.","Cite a district that ran this play and what year three looked like."],"focus":["structure","precision"],"placeholder":"I'll be honest about the timeline: you'll pay now and see the proof in third-grade scores three years out — past two elections. So here's what you'll see sooner:"},
    {"id":"narrative-edu-senior-20","level":"senior","profession":"education","title":"The gym with consequences","scenario":"'Deferred maintenance' is the phrase killing your gym-renovation case — it sounds responsible, even prudent. The reality: a gym that fails code in two years, no home games, assemblies in shifts, and a $2 million bill that becomes $3.4 if you wait. Rename it.","task":"Rewrite the case: 2-3 sentences that replace the euphemism with consequences and a cost curve.","tips":["Kill the euphemism first — 'deferring' this is choosing the expensive path.","Consequence in student terms: no home season for 300 athletes.","The cost curve is the closer: today's number versus the waiting number."],"focus":["impact","precision"],"placeholder":"Let's retire the phrase 'deferred maintenance' — what we're actually deciding is whether this repair costs $2 million now or $3.4 million in three years, with two seasons of home games lost in between."},
    {"id":"narrative-edu-senior-21","level":"senior","profession":"education","title":"The employer partnership pitch","scenario":"You want the regional hospital to host a certified nursing assistant pathway for your juniors and seniors. Their objection will be liability and staff time. Your pitch: they're not doing you a favor — you're solving their vacancy pipeline three years before their competitors do.","task":"Write the 3-4 sentence pitch that leads with their interest and handles their objection.","tips":["Their number first: their own posted CNA vacancies.","Position the school as the supplier, not the supplicant.","Handle liability before they raise it — the state framework already covers it."],"focus":["audience","structure"],"placeholder":"You're carrying nineteen open CNA postings, and every hospital in the region is fishing the same empty pond. I'm proposing we build you a private one:"},
    {"id":"narrative-edu-senior-22","level":"senior","profession":"education","title":"Save the arts program","scenario":"The district's consolidation plan zeroes out your theater program — a rounding error in their spreadsheet, the reason forty kids come to school in yours. Your memo to the superintendent gets one page to move the number back. Data alone won't; story alone can't. Both.","task":"Write the memo's opening 3 sentences: the story, the data, the offer.","tips":["Open with the kid the spreadsheet can't see — one sentence, specific.","Then the numbers that make it strategic: retention, attendance, enrollment draw.","Close with an offer that changes the math: shared staffing, booster revenue."],"focus":["impact","audience"],"placeholder":"The student who leads this fall's production had 41 absences the year before he found the theater program; last year he had six. He's one of forty for whom that room is the reason school works —"},
    {"id":"narrative-edu-senior-23","level":"senior","profession":"education","title":"Compliance into mission","scenario":"The state's new science-of-reading mandate arrives with training hours, documentation, and deadlines — and your draft staff memo reads like the statute. Buried in the compliance is the actual mission: this is the thing that finally works for the kids phonics-free methods failed.","task":"Rewrite the memo opening: mission first, mandate as footnote.","tips":["Lead with the kids this serves, not the statute that requires it.","One line locates the mandate: 'the state now requires what the evidence has said for years.'","Compliance framing produces minimums; mission framing produces effort."],"focus":["audience","impact"],"placeholder":"For years we've watched a handful of kids in every class stall out no matter how good the teaching — the research finally caught up to why, and this training is the answer to it. The state mandate arriving with it is, frankly, the least interesting thing about it."},
    {"id":"narrative-edu-senior-24","level":"senior","profession":"education","title":"The op-ed with one argument","scenario":"The paper gave you 400 words before the bond vote. Your draft crams in every argument — safety, capacity, taxes, athletics, pride — and lands none. An op-ed persuades with one argument, told well, objection included.","task":"Write the op-ed's spine: the one argument, the story that carries it, the objection paragraph.","tips":["Pick the argument that moves the undecided, not the one that moves you.","One image does the work of five statistics in a newspaper.","Give the opposition their best sentence, then answer it — readers trust writers who do."],"focus":["structure","audience"],"placeholder":"On January mornings, the temperature in Room 114 is 54 degrees, and second-graders learn fractions in their coats. Everything else in this bond debate is detail."},
    {"id":"narrative-edu-senior-25","level":"senior","profession":"education","title":"The close that lands the vision","scenario":"Your bond-campaign stump speech ends, currently, with 'so please vote yes on Measure C.' After twelve minutes of story and evidence, the close should re-compress the whole case into something the room carries out the door. Write the last thirty seconds.","task":"Deliver the closing: the vision restated in one breath, the stakes, the specific ask. Speak it aloud.","tips":["Return to the image you opened with — closing the loop lands the speech.","Stakes in one sentence: both futures, side by side.","The ask is concrete: vote yes on C, by mail before the 5th."],"focus":["impact","concision"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-edu-senior-01","level":"senior","profession":"education","title":"Announcing the layoffs","scenario":"The budget failed and four positions are being eliminated. Your all-staff announcement draft spends two paragraphs on the district's fiscal context before the word 'positions' appears. Every reader is scanning for one thing: is it me?","task":"Write the opening 2-3 sentences: the headline, the scope, and when affected staff will know.","tips":["Lead with the fact: four positions, which categories, effective when.","Answer 'is it me' immediately: affected staff hear individually by Friday.","Fiscal context comes after the human question, not before."],"focus":["clarity","audience"],"placeholder":"The failed levy means we are eliminating four positions at the end of this year — two instructional aide roles, one library position, and one clerical. If your position is affected, you will hear it from me personally, in a private meeting, by Friday."},
    {"id":"hard-edu-senior-02","level":"senior","profession":"education","title":"Telling the veteran her program is cut","scenario":"After 22 years, the family-and-consumer-science program is ending, and its teacher — respected, beloved — is being reassigned. She's heard rumors. This conversation is Wednesday; the words you open with will be the ones she replays.","task":"Write your opening 2-3 sentences: the decision first, her standing intact, the path forward real.","tips":["The decision in sentence one — she's endured a week of rumors already.","Separate the program's economics from her worth, explicitly.","The reassignment offer must be concrete, not 'we'll find something.'"],"focus":["clarity","audience"],"placeholder":"I'm ending the FCS program at the end of this year, and I wanted you to hear it from me directly, first. This is enrollment arithmetic — eleven students — and it is not a judgment on 22 years of work I'd put against anyone's."},
    {"id":"hard-edu-senior-03","level":"senior","profession":"education","title":"The clean no to the PTA","scenario":"The PTA wants to fund a spring trip to the state capital — generous, well-organized, and impossible: it lands on testing days and equity rules mean you can't run a trip a third of families can't afford even with subsidies. Your draft 'no' is three paragraphs of gratitude hiding the verdict.","task":"Write the 2-3 sentence no: clear verdict, real reason, and the door left open.","tips":["Say no in the first sentence — gratitude can share the sentence, not replace it.","One real reason beats three polite ones.","Redirect the generosity: name what you could say yes to."],"focus":["clarity","audience"],"placeholder":"I can't approve the capital trip, and I want to be straight about why rather than bury it in thanks: it collides with the state testing window, and we can't run a trip that a third of our families can't join. Here's where that same energy and money would say yes —"},
    {"id":"hard-edu-senior-04","level":"senior","profession":"education","title":"The non-renewal conversation","scenario":"You're not renewing a first-year teacher's contract. She's worked hard; the classroom hasn't come together despite a semester of coaching and two improvement plans. The meeting is tomorrow, and kindness here means clarity — a hedged message she can mishear as 'maybe' would be cruel.","task":"Write your opening 2-3 sentences: the decision, unmistakable, delivered with respect.","tips":["Say 'I am not renewing your contract' — not 'we're moving in a different direction.'","The documented reason in one sentence; the meeting isn't a relitigation.","Respect lives in the delivery and the transition support, not in ambiguity."],"focus":["clarity","impact"],"placeholder":"I've decided not to renew your contract for next year, and I owe you that sentence plainly before anything else. This follows the two improvement plans we've worked through —"},
    {"id":"hard-edu-senior-05","level":"senior","profession":"education","title":"Telling the board the polling is bad","scenario":"The board is emotionally committed to November's bond measure. The poll you commissioned came back: 41% support, and the number gets worse when tax impact is mentioned. Your job tonight is to say the thing nobody on the dais wants to hear.","task":"Write the 2-3 sentence delivery: the number first, what it means, your recommendation.","tips":["The number in sentence one — a wind-up tells them it's bad before you do.","Interpret honestly: this isn't a messaging problem to be workshopped away.","Bring a recommendation; bad news without a path is just weather."],"focus":["clarity","impact"],"placeholder":"The poll came back at 41% support, and it drops to 34% once tax impact is stated — that's not a messaging gap we can close by November. I recommend we pull the measure and spend a year building the case —"},
    {"id":"hard-edu-senior-06","level":"senior","profession":"education","title":"The program-ending letter home","scenario":"The grant that funded the free after-school program wasn't renewed, and it ends in June. For 80 working families this is childcare, not enrichment. Your draft letter leads with a paragraph about grant cycles. Their first question is what happens to my 4 o'clock.","task":"Write the opening 2-3 sentences: the fact, the date, and the help finding alternatives.","tips":["The headline and date first — families need to plan, not to understand grant cycles.","Acknowledge what it actually is for them: childcare they built their jobs around.","Concrete help: the alternatives list, the YMCA partnership, the transition deadline."],"focus":["audience","clarity"],"placeholder":"The after-school program will end on June 6 — our federal grant was not renewed, and I couldn't find replacement funding in time for next year. I know that for many of you this program is what makes your work schedule possible, so here is what we've arranged:"},
    {"id":"hard-edu-senior-07","level":"senior","profession":"education","title":"Behavior, impact, ask — for your AP","scenario":"Your assistant principal undermines decisions after the fact — agrees in leadership meetings, then tells teachers 'that came from upstairs, not me.' It surfaced again this week, verbatim, from two sources. The feedback conversation is today, and vague disappointment won't survive his charm.","task":"Write the feedback in three sentences: the specific behavior, its impact, the clear ask.","tips":["Quote the behavior — 'that came from upstairs, not me' — not a character trait.","Impact on the real thing: a leadership team that can't disagree in private and align in public is not a team.","The ask is binary and checkable: argue with me in this room, own it outside it."],"focus":["clarity","structure"],"placeholder":"Twice this month, teachers have quoted you saying 'that came from upstairs, not me' about decisions you agreed to in this office. That tells staff our leadership team doesn't stand behind its own calls — which unravels every hard decision we make. I need one change:"},
    {"id":"hard-edu-senior-08","level":"senior","profession":"education","title":"Telling the superintendent you'll miss the goal","scenario":"Your school improvement plan promised a 5-point math gain; the winter benchmark says you'll land at 1, maybe 2. The superintendent hears it now, from you, with a diagnosis — or in April, from a spreadsheet, without one. Your draft email hedges the number into fog.","task":"Write the 2-3 sentence message: the miss, the size, the reason, the adjustment.","tips":["State the miss plainly with the projected number — fog now costs double later.","One-sentence diagnosis: what you got wrong in the plan, not in the weather.","The adjustment shows the miss taught you something; that's what she's really reading for."],"focus":["clarity","precision"],"placeholder":"We're going to miss the math goal — winter data projects a 1-to-2-point gain against the 5 we committed to. My diagnosis: we spread the intervention block across all students instead of concentrating on the 60 who needed it most. Here's the second-semester correction:"},
    {"id":"hard-edu-senior-09","level":"senior","profession":"education","title":"The transfer denial, final","scenario":"A persistent parent has requested — for the fourth time — that her daughter be moved out of a teacher's class. You've investigated twice; the placement stands. Each soft no has been heard as 'ask again.' This answer has to be kind, final, and actually final.","task":"Write the 2-3 sentence denial that closes the question without closing the relationship.","tips":["'The answer is no, and it will stay no' — finality is information she deserves.","One sentence of grounds: reviewed twice, placement is sound.","Redirect to what IS available: a joint meeting with the teacher, a check-in structure."],"focus":["clarity","audience"],"placeholder":"I'm not moving Emma, and I want to be honest that this answer is final — asking again won't change it, and I'd rather you spend your energy where it can help. What I can offer, and mean:"},
    {"id":"hard-edu-senior-10","level":"senior","profession":"education","title":"Recommending the closure","scenario":"Tonight you recommend closing Lincoln Elementary — 210 students, 62% capacity, and arithmetic that no longer works. Half the gym went to school there. The kindest version of this speech is the one that doesn't pretend it's not a loss.","task":"Deliver the opening 3 sentences: the recommendation, the honest reason, the loss acknowledged as real. Speak it aloud.","tips":["The recommendation in the first sentence — the room already knows why they came.","Numbers as respect: they deserve the real arithmetic, not softened phrases.","Name the grief without performing it; then commit to what closure must protect."],"focus":["clarity","impact"]},
    {"id":"hard-edu-senior-11","level":"senior","profession":"education","title":"No to the athletic budget","scenario":"Your head football coach — winning record, community following — requested a $40,000 equipment and travel increase. The answer is no; the money went to counselors, and you'd make the same call again. He'll take the no better straight than wrapped, but he will take it to the boosters either way.","task":"Write the 2-3 sentence no: the decision, the real trade-off named, the respect explicit.","tips":["No first, with the number: the $40,000 isn't there this year.","Name where it went — hiding the trade-off invites a worse theory.","Say what you CAN do; a partial yes that's real beats a soft no that isn't."],"focus":["clarity","impact"],"placeholder":"The answer on the $40,000 is no, and I'll tell you exactly where that money went: the second counselor, and I'd make that trade again. What I can do is —"},
    {"id":"hard-edu-senior-12","level":"senior","profession":"education","title":"The pool stays closed","scenario":"The pool's filtration failure is worse than hoped: closed for the season, swim team displaced, PE units scrapped, community lap-swim cancelled. The repair quote arrived Friday and the rumor mill is ahead of you. One message goes to staff, families, and the swim boosters this afternoon.","task":"Write the 2-3 sentence core of the message: the verdict, the season's reality, what's arranged.","tips":["The verdict first: closed through June — kill the hopeful rumors cleanly.","Each audience scans for their own loss; name all three briefly.","The arrangements are the message's real payload: the Y's lanes, the revised PE plan."],"focus":["clarity","structure"],"placeholder":"The pool is closed through the end of the school year — the filtration repair is a full replacement, and it cannot be done mid-season. Swim team practices move to the YMCA starting Monday;"},
    {"id":"hard-edu-senior-13","level":"senior","profession":"education","title":"The decision stands","scenario":"Forty staff signed a letter asking you to reverse the Saturday PD decision. You've read it carefully, and the answer is no — the reasons haven't changed. Respect means a real response: engaging their strongest argument, not restating your announcement louder.","task":"Write the 2-3 sentence reply: their best point engaged honestly, the decision affirmed, the door defined.","tips":["Quote their strongest argument fairly before you answer it — that's the respect.","'I've decided, and here's the reasoning your letter tested' beats repetition.","Define what WOULD reopen it, so 'no' doesn't read as 'never listening.'"],"focus":["structure","audience"],"placeholder":"Your strongest point — that Saturday sessions fall hardest on staff with young children — is real, and it's why we're adding childcare and a remote option. The decision itself stands, and I want to be direct about that rather than hopeful:"},
    {"id":"hard-edu-senior-14","level":"senior","profession":"education","title":"Owning the public error","scenario":"At Monday's board meeting you stated, confidently, that no families had complained about the bus contractor. Tuesday, the clerk found nine logged complaints your office never routed to you. The correction is yours to make at the next meeting — before the clerk's records make it for you.","task":"Write the 2-3 sentence public correction: the error owned plainly, the fact corrected, the fix named.","tips":["Correct the record in the first sentence, in your own voice — 'I told you X; the truth is Y.'","Explain the mechanism without hiding behind it — the routing failure is context, not cover.","The fix makes it a systems story; the speed makes it a credibility story."],"focus":["clarity","impact"],"placeholder":"I need to correct something I told this board Monday: I said we'd received no complaints about the bus contractor, and that was wrong — nine complaints were logged with my office that never reached my desk. Both problems are mine to fix, and here's how:"},
    {"id":"hard-edu-senior-15","level":"senior","profession":"education","title":"No to the board member's project","scenario":"A board member wants his coding-academy pet project in your building next fall, and he's asked you to 'make it work.' It duplicates an existing program, the vendor's results are thin, and your staff have no bandwidth. He influences your budget. The no still has to be a no.","task":"Write the 2-3 sentence no: direct, evidenced, with the political relationship handled by respect rather than surrender.","tips":["A hedge he can hear as 'maybe' guarantees this conversation again in a month.","Ground the no in evidence and mission, not in preference.","Offer the honest alternative: what version, if any, you could pilot and when."],"focus":["clarity","audience"],"placeholder":"I'm not going to bring the academy in next fall, and I'd rather tell you that directly than slow-walk it: it duplicates our existing CS pathway, and the vendor's outcome data doesn't survive a close read. If the goal is more coding seats, here's what I could actually stand behind —"},
    {"id":"hard-edu-senior-16","level":"senior","profession":"education","title":"The expulsion-hearing notification","scenario":"After the weapons-policy violation, district process requires an expulsion hearing, and you're calling the student's mother tonight. She'll remember this call for years. It has to be legally precise, unmistakably clear about what's happening, and humane about what isn't decided yet.","task":"Write your opening 3 sentences for the call: what's happening, what it means, what her rights are.","tips":["Plain words: 'the district is convening an expulsion hearing' — not code she has to decode later.","Separate what's decided (the hearing) from what isn't (the outcome).","Her rights and the timeline in the same breath — advocacy information is part of the kindness."],"focus":["clarity","audience"],"placeholder":"I'm calling because the district is convening an expulsion hearing for Marcus, based on Friday's incident — I want you to hear that from me, with time to prepare, not from a letter. The hearing is a process, not a verdict:"},
    {"id":"hard-edu-senior-17","level":"senior","profession":"education","title":"The front-desk feedback","scenario":"Three families this month described being treated curtly at your front office — the first face of the school. Your office manager is loyal, overworked, and will hear any feedback as an accusation. The conversation still has to happen, specifically enough to change Tuesday morning.","task":"Write the feedback: the pattern named with specifics, the stakes, the concrete ask — 3 sentences.","tips":["Patterns need instances: 'three families this month' with one concrete example.","Stakes without melodrama: the front desk is the school's first sentence to every family.","Ask for observable behavior, and pair it with the workload fix you owe her."],"focus":["clarity","structure"],"placeholder":"Three families this month have told me they left the front office feeling like an interruption — one was a new parent trying to enroll. You are the first experience anyone has of this school, which is why this matters enough to say out loud. Two things, one for each of us:"},
    {"id":"hard-edu-senior-18","level":"senior","profession":"education","title":"The grant is gone","scenario":"The mental-health grant that funds two social workers wasn't renewed, and you've exhausted the alternatives. The two social workers hear first, today; staff hear Thursday. The staff message has to be honest that services are shrinking, without performing optimism you don't feel.","task":"Write the staff message's opening 2-3 sentences: the fact, the human impact, the real plan.","tips":["The loss stated plainly: two positions, ending June 30 — no euphemisms like 'transition.'","Honor what the roles carried; staff know exactly what disappears with them.","The real plan, modestly stated: what's covered, what isn't, what you're still pursuing."],"focus":["clarity","audience"],"placeholder":"Our mental-health grant was not renewed, and with it we lose both social worker positions on June 30 — I've spent six weeks looking for replacement funding and haven't found it. I won't pretend the remaining coverage is equivalent, because you'll see immediately that it isn't. Here's what we can actually hold:"},
    {"id":"hard-edu-senior-19","level":"senior","profession":"education","title":"Your class sizes are going up","scenario":"The staffing formula gives you one fewer second-grade section next year: classes of 27 instead of 22. Mrs. Chen, your strongest second-grade teacher, asked you directly at dismissal whether the rumor is true. It is. She deserves the number and the reason, not reassurance.","task":"Write your answer: the fact confirmed, the number, the reason, and what you fought for — 2-3 sentences.","tips":["Confirm it straight — she asked a factual question and earned a factual answer.","The mechanism in one sentence: enrollment drives sections; the formula is district-wide.","Name what you argued for and lost; honesty about your own limits builds more trust than spin."],"focus":["clarity","audience"],"placeholder":"The rumor is true, and I'd rather you have the real number than the hallway version: second grade goes to three sections of 27 next year. I appealed for the fourth section and lost —"},
    {"id":"hard-edu-senior-20","level":"senior","profession":"education","title":"Your street changes schools","scenario":"The boundary vote passed, and the letter to the 140 affected families goes out tomorrow. For them it isn't policy — it's a kid leaving her friends. The draft leads with the board's rationale. It should lead with what's true for them, and it can't apologize for a decision you'd defend.","task":"Write the letter's opening 2-3 sentences: the fact, the loss acknowledged, the transition made concrete.","tips":["Their fact first: your address is now zoned to Jefferson, starting August.","Acknowledge without apologizing — 'this asks something real of your family' is honest either way.","One concrete transition support per sentence beats a paragraph of empathy."],"focus":["audience","clarity"],"placeholder":"Starting this August, students at your address will attend Jefferson Elementary. I know that sentence lands hard — it means new teachers, a new building, and for some kids, a bus away from their best friend — so here is exactly what we're doing to carry your family across:"},
    {"id":"hard-edu-senior-21","level":"senior","profession":"education","title":"No raise beyond step","scenario":"At the table, the union's proposal is 4% plus step. Your final authority is step only — roughly 1.9% — and today is the day to say so. The room will hear it as an insult unless the arithmetic is naked on the table and your respect for the ask is real.","task":"Write the 2-3 sentence delivery: the position, the arithmetic shown, the ask taken seriously.","tips":["State the position without a wind-up; the table can smell a preamble.","Show the arithmetic that binds you — real constraints are more respectful than vague ones.","Name what you can move on instead: the non-salary items with actual room."],"focus":["clarity","precision"],"placeholder":"My final position on salary is step only — and I'm going to put the whole revenue picture on the table so you can check my arithmetic rather than take my word. Where I do have room, and want to use it:"},
    {"id":"hard-edu-senior-22","level":"senior","profession":"education","title":"Declining the donor's condition","scenario":"A donor offered $200,000 for the library renovation — conditioned on naming it for his late wife and permanently displaying a plaque with language your committee found more memorial than school. The gift is transformative; the condition doesn't fit. Decline the condition without losing the donor.","task":"Write the 2-3 sentence message: the condition declined clearly, the reason principled, the relationship and gift kept open.","tips":["Decline the condition, not the donor — keep those surgically separate.","One principled reason, stated once: naming policy exists to outlive every individual case.","Offer the honorable alternative: the reading room, the collection endowment, the garden."],"focus":["audience","clarity"],"placeholder":"I can't accept the naming condition as proposed, and I want to explain the principle rather than hide behind a policy number: our naming standards have to hold for every future gift, or they hold for none. What I can offer — and would be proud to —"},
    {"id":"hard-edu-senior-23","level":"senior","profession":"education","title":"Terminating the vendor","scenario":"Three months of documented failures — missed deliveries, two temperature violations, a stonewalled audit — and you're terminating the food-service contract. The termination letter will be read by their lawyers; the phone call to their regional manager, whom you like, comes first. Make the call clean.","task":"Write your opening 2-3 sentences for the call: the decision, the grounds, the mechanics.","tips":["The decision is made — open with it, not with 'we need to talk about the contract.'","Grounds by category with dates; the documentation does the arguing.","Mechanics next: notice period, transition, final invoices — clean exits are in the details."],"focus":["clarity","precision"],"placeholder":"We're terminating the contract effective end of month, under the cure-failure clause — I wanted you to hear it from me before the formal notice arrives today. The grounds are the ones we've documented since September:"},
    {"id":"hard-edu-senior-24","level":"senior","profession":"education","title":"Restructuring your own team","scenario":"You're collapsing three coordinator roles into two director roles, which means your leadership team of three must apply for two jobs. They're sitting in front of you now. There is no framing that makes this painless; there is a framing that makes it honest.","task":"Write your opening 3 sentences: the change, what it means for the people in the room, the process and its rules.","tips":["The structural fact first, then its human meaning — don't make them do that math alone.","'Three of you, two roles' said aloud is brutal and necessary; they're doing it silently anyway.","The process must be airtight and stated: external review, timeline, what happens to whoever isn't placed."],"focus":["clarity","structure"],"placeholder":"I'm restructuring the leadership team: the three coordinator roles become two director roles in July, which means the three of you will be applying for two positions. I'm not going to pretend that's anything other than what it is —"},
    {"id":"hard-edu-senior-25","level":"senior","profession":"education","title":"Unbury the bad news","scenario":"Your draft community letter about the state results opens with the robotics trophy, meanders through fall highlights, and finally admits — paragraph four — that math scores dropped 11 points. Everyone will find paragraph four anyway, and the burial will be the story. Flip it.","task":"Rewrite the opening 2-3 sentences: the decline first, sized honestly, with the response attached.","tips":["The bad number leads; a community that hears it from you straight will trust the plan that follows.","Size it precisely — 'declined' invites imagination; '11 points' bounds it.","The robotics trophy survives — later, where it reads as balance instead of camouflage."],"focus":["structure","impact"],"placeholder":"Our state math scores dropped 11 points this year, and I want to lead with that fact rather than make you hunt for it. Here's what we understand about why, and what changes Monday:"}
  ],
  "putting-it-together": [
    {"id":"together-edu-senior-01","level":"senior","profession":"education","title":"Ten minutes, one hard recommendation","scenario":"You have ten minutes at the board to recommend closing Lincoln Elementary — leading with the point, owning the judgment, delivering the hard part with care, and leaving time for the vote. The forty-slide study is backup; you are the argument.","task":"Write the opening 3-4 sentences that integrate the headline, the presence, and the hard message.","tips":["Recommendation first, owned in the first person, with the loss acknowledged in the same breath.","Ten minutes means you speak the argument; the deck answers questions.","Register for a board: evidenced, unhurried, no crescendo."],"focus":["structure","impact"],"placeholder":"I'm recommending we close Lincoln Elementary at the end of next year, and I'll spend my ten minutes on the three numbers that forced that judgment and the two commitments that must come with it. This is a loss — I won't present it as anything else —"},
    {"id":"together-edu-senior-02","level":"senior","profession":"education","title":"The email that has to do everything","scenario":"One email to the superintendent, read on her phone between meetings: the math goal will be missed, here's the diagnosis, here's the corrected plan, and you need her sign-off on the intervention shuffle by Friday. Hard news, ownership, structure, and an ask — five sentences.","task":"Write the full email: finding, diagnosis, plan, ask — tight enough for a phone screen.","tips":["Subject line and first sentence carry the miss; the ask gets its own line.","One sentence each: miss, cause, fix, ask, deadline — no sentence does two jobs.","The tone is the relationship: direct about the miss, confident about the fix."],"focus":["concision","structure"],"placeholder":"Subject: Math goal — projecting a miss, plan attached, need your call by Friday. We'll land at +1 to +2 points against the +5 committed;"},
    {"id":"together-edu-senior-03","level":"senior","profession":"education","title":"One shortfall, two registers","scenario":"The $540,000 shortfall goes to two audiences today: the board chair, who needs the fiduciary framing and the decision ahead, and your staff, who need to know what it means for their jobs and their classrooms. Same fact, entirely different sentences.","task":"Write the one-sentence version for the chair and the 2-sentence version for staff.","tips":["The chair gets altitude: size, cause, the decision the board will face and when.","Staff get their own stake first: what this does and doesn't mean for positions.","Same number in both — audiences compare notes."],"focus":["audience","clarity"],"placeholder":"To the chair: We're carrying a $540,000 structural shortfall into budget season — driven by enrollment, not spending — and the board will face a cuts-versus-reserves decision in March. To staff: You'll hear about a $540,000 budget gap, and before the rumor mill sizes it for you:"},
    {"id":"together-edu-senior-04","level":"senior","profession":"education","title":"The first-hour crisis message","scenario":"A school bus was rear-ended this morning; eleven students were checked at the hospital, two kept for observation, everyone stable. Rumors are outpacing facts. The message to all families goes out within the hour — clear, structured, calm, exact, and human, all at once.","task":"Write the full first-hour message: 4-5 sentences integrating the facts, the status, the next update, and the tone.","tips":["Facts first, in order of what parents fear most: everyone is stable.","Exact numbers beat soothing vagueness — precision IS the reassurance.","Commit to the next update by time, not by 'as we learn more.'"],"focus":["clarity","audience"],"placeholder":"This morning, Bus 7 was struck from behind on Route 9; all students are safe and stable. Eleven students were examined at Mercy General as a precaution — nine have been released to families, and two are being kept for observation, both alert and in good condition."},
    {"id":"together-edu-senior-05","level":"senior","profession":"education","title":"Taking over the struggling school","scenario":"You're the fourth principal in six years at a school the state just flagged for intervention. Your first all-staff address must acknowledge the past without flogging it, lead with what changes, project decided leadership, and stay honest about the year ahead — in the first two minutes.","task":"Deliver the opening 4-5 sentences of the address. Speak it aloud.","tips":["One sentence for the past — named, not narrated — then face forward.","Say one thing you've already decided and one thing you'll decide only after listening.","The register is steady conviction; a fourth-principal pep talk would insult the room."],"focus":["impact","audience"]},
    {"id":"together-edu-senior-06","level":"senior","profession":"education","title":"Self-edit the referendum letter","scenario":"Your referendum letter draft is 700 words: three openings, buried tax figures, two arguments repeated, the ask in the last line. The mail piece allows 250 words. Edit against everything you know — point first, audience's question first, evidence exact, one argument per paragraph, ask visible.","task":"Write the edited letter's first 4 sentences: the ask, the cost, the case, the objection handled.","tips":["The ask and the monthly cost in the first two sentences — voters check those first.","One argument, told once, with one number.","Read it as a skeptical renter and a fixed-income homeowner before sending."],"focus":["concision","structure"],"placeholder":"On May 6, we're asking you to vote yes on Measure C — $11 a month for the median home — to replace the two buildings your children learn in. Here is the whole case in one paragraph:"},
    {"id":"together-edu-senior-07","level":"senior","profession":"education","title":"The state of the school in 90 seconds","scenario":"The district gala gives each principal ninety seconds. Yours must land the reading gains, be honest about the math slide, thank the staff without a list, and leave the donors with one sentence they'll repeat. Ninety seconds is about 200 words — every one auditions.","task":"Deliver the full 90-second address. Speak it aloud.","tips":["One result, one honest gap, one vision sentence — that's the whole architecture.","The honest gap is what makes the result believable.","Write the repeatable sentence first, then build the ninety seconds around it."],"focus":["concision","impact"]},
    {"id":"together-edu-senior-08","level":"senior","profession":"education","title":"Five pages into five sentences","scenario":"Your five-page attendance-initiative memo is circling the district office unread. The assistant superintendent asked for 'the short version by Thursday.' The short version isn't a summary of the memo — it's the memo, done right: point, evidence, plan, ask, deadline.","task":"Write the five-sentence version: one sentence per job.","tips":["Sentence one is the finding and its size; sentence five is the ask and its date.","Each middle sentence earns its place: evidence, plan, cost — one apiece.","If a sentence summarizes another sentence, one of them goes."],"focus":["concision","structure"],"placeholder":"Chronic absenteeism hit 18% — 112 students — and it's costing us both outcomes and $220,000 in attendance-linked funding. The driver, from our family calls, is transportation gaps on the east side —"},
    {"id":"together-edu-senior-09","level":"senior","profession":"education","title":"Opening the forum after the vote","scenario":"The boundary decision passed 4-3 last week; tonight's forum is for the losing side's neighborhoods. Your opening must own the decision without relitigating it, honor the anger without surrendering to it, structure the evening, and make the room believe the transition promises — in three minutes.","task":"Deliver the opening 4-5 sentences. Speak it aloud.","tips":["Own the decision in your own voice even though the board cast the votes.","Name what tonight is for — the transition — and what it cannot be: a re-vote.","Every promise gets a name, a date, or a number, or it doesn't get said."],"focus":["audience","structure"]},
    {"id":"together-edu-senior-10","level":"senior","profession":"education","title":"The statement legal already reviewed","scenario":"A staff member is under investigation; counsel has approved four sentences' worth of sayable facts. The community statement has to be legally clean AND humanly real — a wall of 'no comment' will read as cover-up. Everything you know about precision, audience, and presence fits inside four sentences.","task":"Write the four-sentence statement: the sayable facts, the boundary as principle, the process, the values.","tips":["Say everything you can say, fully — generosity inside limits reads as candor.","State the boundary as a protection, not a shield: due process serves the truth.","One sentence of values, concrete: what the school owes students while process runs."],"focus":["precision","audience"],"placeholder":"On Monday we placed a staff member on administrative leave and referred the matter to the district and to law enforcement — those two facts are confirmed, and I will not characterize the allegations while the investigation runs, because due process protects the truth for everyone, including students."},
    {"id":"together-edu-senior-11","level":"senior","profession":"education","title":"The closure with a future attached","scenario":"The closure recommendation passed. Tonight's message to Lincoln families must deliver the hard fact cleanly, honor what the school was, and make the receiving school's promise concrete enough to plan around — grief and logistics in one letter, neither crowding out the other.","task":"Write the letter's opening 4 sentences: the fact, the honor, the concrete future, the first date.","tips":["The decision first, dated, without hedging — families need to plan.","One sentence of honor with a specific in it, not a plaque inscription.","The future in checkable details: teachers moving with students, the June visit day."],"focus":["audience","impact"],"placeholder":"The board voted last night to close Lincoln Elementary at the end of this school year, and your children will attend Roosevelt starting in August. Lincoln taught three generations of this neighborhood to read, and that history deserves better than a form letter —"},
    {"id":"together-edu-senior-12","level":"senior","profession":"education","title":"The cover memo that decides","scenario":"The board packet for the budget vote is 90 pages. Your one-page cover memo is the only page all seven members will read. It must state the recommendation, the three numbers that matter, the honest risk, and exactly what motion you need — decision-ready, no tour of the appendix.","task":"Write the memo's first 4 sentences: recommendation, key numbers, named risk, requested motion.","tips":["The motion you need appears twice: sentence one and the last line.","Three numbers maximum — the packet holds the rest.","Name the risk yourself; a risk the board discovers reads worse than one you disclosed."],"focus":["structure","concision"],"placeholder":"I recommend the board adopt the attached budget: it closes the $540,000 gap with $310,000 in cuts and $230,000 from reserves, and it protects every classroom position. Three numbers tell the story —"},
    {"id":"together-edu-senior-13","level":"senior","profession":"education","title":"One incident, three audiences","scenario":"A student brought a knife to school; protocol worked, no one was hurt, discipline is underway. By 5 p.m. you owe three versions: staff (operational detail), families (reassurance with facts), and the press (precise, quotable, bounded). Same truth, three calibrations.","task":"Write the first two sentences of each version — six sentences total.","tips":["Staff get the operational: what protocol ran, what to say to students tomorrow.","Families get the answer to their real question first: safety, then process.","Press get short declarative sentences that can't be cut into something worse."],"focus":["audience","precision"],"placeholder":"To staff: This morning a student surrendered a knife at the Building B entrance during bag check — the protocol worked exactly as drilled. To families: Your children are safe, and I want you to have the facts before the group chats do —"},
    {"id":"together-edu-senior-14","level":"senior","profession":"education","title":"The year-end letter, whole","scenario":"Your year-end letter to the community has to hold four things at once: the reading gains earned, the math slide unhidden, gratitude with specifics, and next year's one big commitment. Most drafts do one of these well. The craft is the seams.","task":"Write the letter's first 4 sentences — one per job, seamed into a single voice.","tips":["Lead with the strongest true thing, follow immediately with the honest gap — that order earns trust.","Gratitude with a specific beats gratitude with an adjective.","One commitment for next year, measurable, so June's letter can be graded against it."],"focus":["structure","impact"],"placeholder":"This year our third-graders posted the school's largest reading gain in a decade — nine points — and our middle school math scores fell, and you deserve both sentences in the same paragraph."},
    {"id":"together-edu-senior-15","level":"senior","profession":"education","title":"Thirty seconds with the superintendent","scenario":"You catch the superintendent in the parking lot after the cabinet meeting. Thirty seconds to land the counselor ask before budget lines lock Friday: the point first, the one number that carries it, the specific request, and a close that gets a real answer instead of a nod.","task":"Deliver the thirty-second ask. Speak it aloud.","tips":["Open with the ask, not the wind-up — parking lots don't have context budgets.","One number: 480 students per counselor against 250 recommended.","Close on a question that requires a decision: 'Can I count on it in Friday's draft?'"],"focus":["concision","impact"]},
    {"id":"together-edu-senior-16","level":"senior","profession":"education","title":"The negotiation opener, complete","scenario":"Contract talks open Monday. Your opening statement must state the fiscal constraint as checkable arithmetic, name the shared retention problem, set a working tone, and put your first real move on the table — firm, respectful, structured, and short enough to keep the room's attention.","task":"Write the full opening statement: 4-5 sentences.","tips":["Arithmetic first — invite them to check it; transparency is your credibility deposit.","The shared problem gives both sides a reason to solve rather than win.","End with a real move, not a platitude: the non-salary item you're opening with."],"focus":["structure","audience"],"placeholder":"Here's the revenue picture, and I want your team to check every number: 2.1% new money, $180,000 of it already committed to the step schedule. What we share is a retention problem — we both lost people we couldn't afford to lose last year —"},
    {"id":"together-edu-senior-17","level":"senior","profession":"education","title":"The apology that carries everything","scenario":"The notification failure during last month's lockdown — families learned from the news before the school — has been investigated, and the failure was in your office's protocol. The public apology must own it plainly, correct the record precisely, and restore confidence structurally. No passive voice survives contact.","task":"Write the apology's first 4 sentences: the ownership, the facts, the fix, the check on the fix.","tips":["'I' owns the failure; 'we' shares the fix — get the pronouns right.","Correct the record with the actual timeline, minute by minute where it matters.","The fix needs a verification: who tests it, how often, reported where."],"focus":["clarity","impact"],"placeholder":"Families should have heard from this school before they heard from the news, and they didn't — that failure happened in my office, under my protocol, and I own it without qualification. Here is what actually happened, by the clock:"},
    {"id":"together-edu-senior-18","level":"senior","profession":"education","title":"The email before the contentious vote","scenario":"Thursday the board votes on the seven-period schedule, and it's close. Your email to the chair tonight must summarize the case in one paragraph, arm her against the two objections she'll face on the dais, and respect the line between informing the chair and lobbying the vote.","task":"Write the full email: 5-6 sentences — the case, the two objections pre-armed, the boundary kept.","tips":["One paragraph of case: the recommendation, the strongest evidence, the cost.","For each objection, give the answer in one sentence she can say aloud.","Close by respecting the vote: the decision is theirs; your job was the evidence."],"focus":["structure","audience"],"placeholder":"Ahead of Thursday, here is the case in one paragraph and the two hard questions I expect from the dais. The recommendation: seven periods, which restores arts access for 300 students at a cost of 1.4 FTE —"},
    {"id":"together-edu-senior-19","level":"senior","profession":"education","title":"The update that fits a voicemail","scenario":"The water-main situation is evolving: repairs on schedule, reopening tomorrow at 10, buses on the two-hour-delay plan, breakfast still served. The superintendent is in hearings all day; she gets a voicemail. Forty seconds — status, decision, exceptions, next update. Nothing twice.","task":"Deliver the forty-second voicemail. Speak it aloud.","tips":["Status in the first sentence: reopening tomorrow, 10 a.m., repairs on track.","Then only what deviates from normal — she knows what normal is.","End with the next update time and your cell — then stop talking."],"focus":["concision","clarity"]},
    {"id":"together-edu-senior-20","level":"senior","profession":"education","title":"Three minutes to defend the budget","scenario":"The council gives each principal three minutes at the public budget hearing. Yours must lead with the point, ground every claim in a checkable number, humanize the 74 lost students, pre-empt the 'cut administration' objection, and end on the specific dollar ask — a decathlon in 400 words.","task":"Write the full three-minute testimony's first 5 sentences, hitting point, number, human stake, and objection.","tips":["The ask opens and closes; the middle earns it.","Alternate altitude: number, face, number — rhythm keeps a tired council listening.","Pre-empt the objection in one sentence and move — don't camp on defense."],"focus":["structure","impact"],"placeholder":"I'm here to ask you to restore $310,000 — and I'll spend my three minutes showing you exactly what it buys and what its absence costs. Start with 74: the students we lost last year, most to programs this budget eliminates —"},
    {"id":"together-edu-senior-21","level":"senior","profession":"education","title":"Translate the district memo","scenario":"The district's memo on the new attendance-recovery policy is 900 words of statute citations and acronyms, and you're required to send it home. Requirement met is not communication done: your families need 120 words that lead with what changes for their child and what they must do.","task":"Write the family version: 4 sentences — what changes, who it affects, what to do, where the full policy lives.","tips":["Open with the parent's stake: what happens now when your child misses ten days.","Every acronym dies or gets defined in three words.","Attach the district memo for the record; write yours for the refrigerator door."],"focus":["audience","concision"],"placeholder":"Starting in January, when a student reaches ten absences, you'll get a call from us to build a catch-up plan — before grades are affected, not after."},
    {"id":"together-edu-senior-22","level":"senior","profession":"education","title":"The departure letter","scenario":"After nine years, you're leaving in June for a district role. The community letter must announce it cleanly, resist the fifteen-paragraph memoir, spotlight the school's momentum rather than your own, and make the transition boring in the best way — named, dated, steady.","task":"Write the letter's first 4 sentences: the news, the timing, the continuity, the gratitude with one specific.","tips":["The news in sentence one — burying your own headline fails the course.","Continuity is the payload: who leads the transition and what doesn't change.","One specific memory of the community beats a paragraph of adjectives."],"focus":["clarity","audience"],"placeholder":"In June, after nine years, I'll be leaving to lead the district's curriculum office — and I want you to hear it from me, with a full semester of runway, not from a board agenda. The school's momentum doesn't depend on me:"},
    {"id":"together-edu-senior-23","level":"senior","profession":"education","title":"The legislator's one-pager","scenario":"A state senator visits Thursday for twenty minutes, and her aide asked for a one-pager. Whatever you hand her must survive the car ride: the school in three numbers, the one policy ask stated as a bill position, and a story her floor speech could borrow. One page, her language, your facts.","task":"Write the one-pager's first 4 sentences: the school in numbers, the ask, the story lead.","tips":["Her currency is constituents and bills — frame both in the first two sentences.","One ask; a one-pager with three asks makes none.","Write the story sentence so it works verbatim in a floor speech."],"focus":["audience","concision"],"placeholder":"You represent 620 of our students, and this year 112 of them were chronically absent — a problem Senate Bill 214 would fund us to fix. Our ask is one line: support the transportation-grant provision in SB 214 as written."},
    {"id":"together-edu-senior-24","level":"senior","profession":"education","title":"The last word of a rough night","scenario":"The forum ran two hours over; the anger was real and mostly aimed at you. The last agenda line is yours: a two-minute close that neither surrenders the decision nor dismisses the room — what was heard, what changes because of tonight, what stands, and when they'll see the follow-through.","task":"Deliver the two-minute close's first 4-5 sentences. Speak it aloud.","tips":["Prove you heard by quoting the room accurately — two concerns, their words.","Name one thing tonight actually changed; a close where nothing moved confirms their cynicism.","Restate what stands without re-arguing it, and date the follow-through."],"focus":["audience","impact"]},
    {"id":"together-edu-senior-25","level":"senior","profession":"education","title":"The hardest day","scenario":"Capstone: the state flagged your school for intervention this morning, the news has the story, staff are shaken, and families are calling. By tonight you send one message to the whole community — headline first, numbers exact, the gap owned, the plan structured, the register human, the length merciful. Everything this course taught, on the day it's hardest to use.","task":"Write the full message: 6-7 sentences integrating point-first structure, precise evidence, ownership, and a concrete path.","tips":["The designation and what it means, plainly, in the first two sentences — outrun the rumor version.","Own the gap with a number before pivoting to the plan; the pivot earns nothing until the fact lands.","End with the first checkable milestone and its date — hope with a deadline."],"focus":["structure","impact"],"placeholder":"This morning the state placed our school on its intervention list, based on two years of declining math scores — and before I tell you the plan, I want to be plain about the fact: our students are behind where they should be, and that is mine to own."}
  ]
};
